   204→    private String getApplicantNickName(Long userId) {
   205→        try {
   206→            UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
   207→            if (user != null && user.getNickName() != null) {
   208→                return user.getNickName();
   209→            }
   210→            return "用户" + userId;
   211→        } catch (Exception e) {
   212→            log.warn("[1822-PermApply] getApplicantNickName error userId={}", userId, e);
   213→            return "用户" + userId;
   214→        }
   215→    }
   216→
   217→    // ========== Notification via gRPC ==========
   218→
   219→    @Async
   220→    public void notifyAdminsAsync(PermissionRequestEntity request, String documentName,
   221→                                   String applicantNickName, String spaceName) {
   222→        try {
   223→            List<Long> adminUserIds = spaceQueryManager.getAdminUsersWithWorkBenchManagePermission(request.getSpaceId());
   224→            if (CollUtil.isEmpty(adminUserIds)) {
   225→                log.warn("[1822-PermApply] notifyAdmins no admins spaceId={}", request.getSpaceId());
   226→                return;
   227→            }
   228→            log.info("[1822-PermApply] notifyAdmins requestId={} documentId={} approverCount={}",
   229→                request.getId(), request.getDocumentId(), adminUserIds.size());
   230→
   231→            Map<String, Object> extras = new HashMap<>();
   232→            extras.put("requestId", request.getId());
   233→            extras.put("spaceName", spaceName);
   234→            extras.put("applicantUserId", String.valueOf(request.getApplicantUserId()));
   235→            extras.put("applicantNickName", applicantNickName);
   236→            extras.put("documentId", request.getDocumentId());
   237→            extras.put("documentName", documentName);
   238→            extras.put("requestedPermissionType", request.getRequestedPermissionType());
   239→            extras.put("status", request.getStatus());
   240→
   241→            Map<String, Object> bodyMap = new HashMap<>();
   242→            bodyMap.put(BODY_EXTRAS, extras);
   243→            String bodyJson = JSONUtil.toJsonStr(bodyMap);
   244→
   245→            apitableGrpcClientService.createNotification(
   246→                DOCUMENT_PERMISSION_REQUEST,
   247→                String.valueOf(request.getApplicantUserId()),
   248→                adminUserIds.stream().map(String::valueOf).collect(Collectors.toList()),
   249→                request.getDocumentId(),
   250→                request.getSpaceId(),
   251→                bodyJson,
   252→                true
   253→            );
   254→
   255→            log.info("[1822-PermApply] notifyAdmins done requestId={} adminCount={}", request.getId(), adminUserIds.size());
   256→        } catch (Exception e) {
   257→            log.error("[1822-PermApply] ERROR notifyAdmins requestId={} error={}", request.getId(), e.getMessage(), e);
   258→        }
   259→    }
   260→
   261→    @Async
   262→    public void notifyApplicantAsync(PermissionRequestEntity request, String documentName, String spaceName) {
   263→        try {
   264→            Map<String, Object> extras = new HashMap<>();
   265→            extras.put("requestId", request.getId());
   266→            extras.put("documentId", request.getDocumentId());
   267→            extras.put("documentName", documentName);
   268→            extras.put("spaceId", request.getSpaceId());
   269→            extras.put("spaceName", spaceName);
   270→            extras.put("requestedPermissionType", request.getRequestedPermissionType());
   271→            extras.put("status", request.getStatus());
   272→
   273→            Map<String, Object> bodyMap = new HashMap<>();
   274→            bodyMap.put(BODY_EXTRAS, extras);
   275→            String bodyJson = JSONUtil.toJsonStr(bodyMap);
   276→
   277→            // fromUserId = "0" avoids apitable's "don't notify self" filter
   278→            apitableGrpcClientService.createNotification(
   279→                "permission_apply_submitted",
   280→                "0",
   281→                Collections.singletonList(String.valueOf(request.getApplicantUserId())),
   282→                request.getDocumentId(),
   283→                request.getSpaceId(),
   284→                bodyJson,
   285→                false
   286→            );
   287→
   288→            log.info("[1822-PermApply] notifyApplicant requestId={} applicantUserId={} documentId={}",
   289→                request.getId(), request.getApplicantUserId(), request.getDocumentId());
   290→        } catch (Exception e) {
   291→            log.error("[1822-PermApply] ERROR notifyApplicant requestId={} error={}", request.getId(), e.getMessage(), e);
   292→        }
   293→    }
   294→
   295→    // ========== List / Count ==========
   296→
   297→    @Override
   298→    public List<PermissionRequestVo> getMyRequests(Long userId, String status, int page, int pageSize) {
   299→        int offset = (page - 1) * pageSize;
   300→        List<PermissionRequestEntity> entities = baseMapper.selectByApplicantUserId(userId, status, offset, pageSize);
   301→        if (CollUtil.isEmpty(entities)) {
   302→            return Collections.emptyList();
   303→        }
   304→        return entities.stream().map(e -> {
   305→            String docName = "";
   306→            String spaceName = "";
   307→            try {
   308→                SpaceNodeEntity node = getSpaceNodeByNodeIdSafe(e.getDocumentId());
   309→                docName = node != null ? node.getName() : "";
   310→            } catch (Exception ex) {
   311→                log.debug("[1822-PermApply] Node not found: {}", e.getDocumentId());
   312→            }
   313→            try {
   314→                SpaceEntity space = spaceService.getBySpaceId(e.getSpaceId());
   315→                spaceName = space != null && space.getName() != null ? space.getName() : "";
   316→            } catch (Exception ex) {
   317→                log.debug("[1822-PermApply] Space not found: {}", e.getSpaceId());
   318→            }
   319→            return buildVo(e, docName, spaceName);
   320→        }).collect(Collectors.toList());
   321→    }
   322→
   323→    @Override
   324→    public int countMyRequests(Long userId, String status) {
   325→        return baseMapper.countByApplicantUserId(userId, status);
   326→    }
   327→
   328→    // ========== Legacy methods (not used - kept for interface compatibility) ==========
   329→
   330→    @Override
   331→    public void approve(Long notificationId, Long approverUserId) {
   332→        throw new UnsupportedOperationException("Use approveByRequestId instead");
   333→    }
   334→
   335→    @Override
   336→    public void reject(Long notificationId, Long approverUserId) {
   337→        throw new UnsupportedOperationException("Use rejectByRequestId instead");
   338→    }
   339→
   340→    // ========== Approve / Reject (by requestId) ==========
   341→
   342→    @Override
   343→    @Transactional(rollbackFor = Exception.class)
   344→    public void approveByRequestId(String requestId, Long notificationId, Long approverUserId) {
   345→        PermissionRequestEntity request = validateAndGetRequest(requestId, approverUserId);
   346→
   347→        String approverNickName = getApproverNickName(approverUserId);
   348→
   349→        // Get applicant unitId
   350→        UnitMemberVo applicantMember = apitableGrpcClientService.findUnitMemberVo(
   351→                List.of(request.getApplicantUserId()), request.getSpaceId())
   352→            .stream().findFirst().orElse(null);
   353→        ExceptionUtil.isNotNull(applicantMember, PermissionRequestException.APPLICANT_UNIT_NOT_FOUND);
   354→        Long unitId = applicantMember.getUnitId();
   355→        ExceptionUtil.isNotNull(unitId, PermissionRequestException.APPLICANT_UNIT_NOT_FOUND);
   356→
   357→        // Map permission type to node role
   358→        String nodeRole = mapPermissionTypeToNodeRole(request.getRequestedPermissionType());
   359→
   360→        // Add node role
   361→        Long spaceNodeId = parseSpaceNodeId(request.getDocumentId());
   362→        if (spaceNodeId != null) {
   363→            nodeRoleUpdateManager.addNodeRole(approverUserId, request.getSpaceId(), spaceNodeId, nodeRole,
   364→                Collections.singletonList(unitId));
   365→        }
   366→
   367→        // Update permission request status in collabspace
   368→        baseMapper.updateStatusById(request.getId(), STATUS_APPROVED, approverUserId);
   369→
   370→        // Update notification extras in apitable (via gRPC)
   371→        apitableGrpcClientService.updateNotificationExtras(notificationId, STATUS_APPROVED,
   372→            String.valueOf(approverUserId), approverNickName);
   373→
   374→        // Mark notification as read in apitable (via gRPC)
   375→        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);
   376→
   377→        log.info("[1822-PermApply] APPROVE requestId={} approverUserId={} applicantUserId={} documentId={} nodeRole={}",
   378→            request.getId(), approverUserId, request.getApplicantUserId(), request.getDocumentId(), nodeRole);
   379→    }
   380→
   381→    @Override
   382→    @Transactional(rollbackFor = Exception.class)
   383→    public void rejectByRequestId(String requestId, Long notificationId, Long approverUserId) {
   384→        PermissionRequestEntity request = validateAndGetRequest(requestId, approverUserId);
   385→
   386→        String approverNickName = getApproverNickName(approverUserId);
   387→
   388→        // Update permission request status
   389→        baseMapper.updateStatusById(request.getId(), STATUS_REJECTED, approverUserId);
   390→
   391→        // Update notification extras in apitable (via gRPC)
   392→        apitableGrpcClientService.updateNotificationExtras(notificationId, STATUS_REJECTED,
   393→            String.valueOf(approverUserId), approverNickName);
   394→
   395→        // Mark notification as read in apitable (via gRPC)
   396→        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);
   397→
   398→        log.info("[1822-PermApply] REJECT requestId={} approverUserId={} applicantUserId={} documentId={}",
   399→            request.getId(), approverUserId, request.getApplicantUserId(), request.getDocumentId());
   400→    }
   401→
   402→    @Override
   403→    public void ignoreByRequestId(String requestId, Long notificationId, Long approverUserId) {
   404→        validateRequestForApprover(requestId, approverUserId);
   405→        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);
   406→        log.info("[1822-PermApply] IGNORE requestId={} notificationId={} approverUserId={}", requestId, notificationId, approverUserId);
   407→    }
   408→
   409→    @Override
   410→    public void reapproveByRequestId(String requestId, Long notificationId, Long approverUserId) {
   411→        validateRequestForApprover(requestId, approverUserId);
   412→        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, false);
   413→        log.info("[1822-PermApply] REAPPROVE requestId={} notificationId={} approverUserId={}", requestId, notificationId, approverUserId);
   414→    }
   415→
   416→    // ========== Validation Helpers ==========
   417→
   418→    /**
   419→     * Validates requestId exists and approver is admin. Does NOT check PENDING status.
   420→     * Used for reapprove, which can act on already-processed requests.
   421→     */
   422→    private void validateRequestForApprover(String requestId, Long approverUserId) {
   423→        if (requestId == null || requestId.isBlank()) {
   424→            ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
   425→        }
   426→        PermissionRequestEntity request = baseMapper.selectById(requestId);
   427→        if (request == null) {
   428→            log.warn("[1822-PermApply] validate requestNotFound requestId={}", requestId);
   429→            ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
   430→        }
   431→        validateApproverIsAdmin(approverUserId, request.getSpaceId());
   432→    }
   433→
   434→    private PermissionRequestEntity validateAndGetRequest(String requestId, Long approverUserId) {
   435→        if (requestId == null || requestId.isBlank()) {
   436→            ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
   437→        }
   438→        PermissionRequestEntity request = baseMapper.selectById(requestId);
   439→        if (request == null) {
   440→            log.warn("[1822-PermApply] validate requestNotFound requestId={}", requestId);
   441→            ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
   442→        }
   443→        if (!STATUS_PENDING.equals(request.getStatus())) {
   444→            log.warn("[1822-PermApply] validate alreadyProcessed requestId={} status={}",
   445→                request.getId(), request.getStatus());
   446→            ExceptionUtil.isTrue(false, PermissionRequestException.REQUEST_ALREADY_PROCESSED);
   447→        }
   448→        validateApproverIsAdmin(approverUserId, request.getSpaceId());
   449→        return request;
   450→    }
   451→
   452→    private void validateApproverIsAdmin(Long approverUserId, String spaceId) {
   453→        boolean isAdmin = spaceQueryManager.isUserSpaceAdmin(approverUserId, spaceId);
   454→        ExceptionUtil.isTrue(isAdmin, PermissionRequestException.INSUFFICIENT_PERMISSIONS);
   455→    }
   456→
   457→    private String getApproverNickName(Long approverUserId) {
   458→        try {
   459→            UserSimpleInfoVo user = apitableGrpcClientService.getUserById(approverUserId);
   460→            return user != null && user.getNickName() != null ? user.getNickName() : "";
   461→        } catch (Exception e) {
   462→            return "";
   463→        }
   464→    }
   465→
   466→    private Long parseSpaceNodeId(String documentId) {
   467→        try {
   468→            return Long.parseLong(documentId);
   469→        } catch (NumberFormatException e) {
   470→            return getSpaceNodeIdByAppNodeId(documentId);
   471→        }
   472→    }
   473→
   474→    private Long getSpaceNodeIdByAppNodeId(String appNodeId) {
   475→        try {
   476→            List<SpaceNodeEntity> nodes = spaceNodeService.listByAppSpaceNodeIds(Collections.singletonList(appNodeId));
   477→            if (CollUtil.isNotEmpty(nodes)) {
   478→                return nodes.get(0).getId();
   479→            }
   480→        } catch (Exception e) {
   481→            log.warn("[1822-PermApply] getSpaceNodeIdByAppNodeId failed appNodeId={}", appNodeId, e);
   482→        }
   483→        return null;
   484→    }
   485→
   486→    private String mapPermissionTypeToNodeRole(String requestedPermissionType) {
   487→        return switch (requestedPermissionType) {
   488→            case "READ" -> READER;
   489→            case "EDIT" -> EDITOR;
   490→            case "MANAGE" -> MANAGER;
   491→            default -> READER;
   492→        };
   493→    }
   494→
   495→    private PermissionRequestVo buildVo(PermissionRequestEntity entity, String documentName, String spaceName) {
   496→        return PermissionRequestVo.builder()
   497→            .id(entity.getId())
   498→            .documentId(entity.getDocumentId())
   499→            .documentName(documentName)
   500→            .spaceId(entity.getSpaceId())
   501→            .spaceName(spaceName)
   502→            .requestedPermissionType(entity.getRequestedPermissionType())
   503→            .status(entity.getStatus())
   504→            .createdAt(entity.getCreatedAt())
   505→            .build();
   506→    }
   507→}
