package com.yottastudios.ns.collabspace.control.controller;

import com.yottastudios.ns.collabspace.control.ro.DocumentPermissionRequestRo;
import com.yottastudios.ns.collabspace.control.service.IPermissionRequestService;
import com.yottastudios.ns.collabspace.control.vo.PermissionRequestVo;
import com.yottastudios.ns.collabspace.core.support.ResponseData;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.annotation.Resource;
import jakarta.validation.Valid;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;

/**
 * Document permission request API.
 */
@Slf4j
@RestController
@Tag(name = "Permission Request")
@ApiResource(path = "/documents")
public class DocumentPermissionRequestController {

    @Resource
    private IPermissionRequestService permissionRequestService;

    /**
     * Submit document permission request.
     * <p>Accepts either: node_id (dst prefix) or primary key id (Long).
     * When user has no doc permission, frontend only has spaceNodeId (pk) from URL, not dst id.</p>
     */
    @PostResource(path = "/{nodeIdOrPk}/permission-requests", requiredPermission = false)
    @Operation(summary = "Submit document permission request")
    public ResponseData<PermissionRequestVo> submitRequest(
        @Parameter(description = "Node ID (dstxxx) or primary key id (number, e.g. spaceNodeId)")
        @PathVariable("nodeIdOrPk") String nodeIdOrPk,
        @Valid @RequestBody DocumentPermissionRequestRo ro) {
        log.info("[1822-PermApply] submit entry nodeIdOrPk={} requestedType={}", nodeIdOrPk, ro != null ? ro.getRequestedPermissionType() : null);
        PermissionRequestVo vo = permissionRequestService.submitRequest(nodeIdOrPk, ro);
        return ResponseData.success(vo);
    }
}

