package com.apitable.player.controller;

import com.apitable.core.support.ResponseData;
import com.apitable.player.service.IPermissionRequestService;
import com.apitable.player.vo.PermissionRequestVo;
import com.apitable.shared.component.scanner.annotation.ApiResource;
import com.apitable.shared.component.scanner.annotation.GetResource;
import com.apitable.shared.context.SessionContext;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.annotation.Resource;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

/**
 * Player permission request API - my applications list.
 */
@Slf4j
@RestController
@Tag(name = "Player System - Permission Request API")
@ApiResource(path = "/player/permission-requests")
public class PlayerPermissionRequestController {

    @Resource
    private IPermissionRequestService permissionRequestService;

    /**
     * Get my permission requests with pagination.
     */
    @GetResource(path = "", requiredPermission = false)
    @Operation(summary = "Get my permission requests")
    public ResponseData<Map<String, Object>> getMyRequests(
        @Parameter(description = "Page number") @RequestParam(defaultValue = "1") int page,
        @Parameter(description = "Page size") @RequestParam(defaultValue = "20") int pageSize,
        @Parameter(description = "Status: PENDING, APPROVED, REJECTED") @RequestParam(required = false) String status) {
        Long userId = SessionContext.getUserId();
        if (userId == null) {
            return ResponseData.success(new HashMap<>(Map.of("records", List.of(), "total", 0)));
        }
        List<PermissionRequestVo> records = permissionRequestService.getMyRequests(userId, status, page, pageSize);
        int total = permissionRequestService.countMyRequests(userId, status);
        Map<String, Object> data = new HashMap<>();
        data.put("records", records);
        data.put("total", total);
        return ResponseData.success(data);
    }
}

