import org.springframework.web.bind.annotation.RestController;

/**
 * Document permission request API.
 */
@Slf4j
@RestController
@Tag(name = "Player System - Document Permission Request API")
@ApiResource(path = "/documents")
public class DocumentPermissionRequestController {

    @Resource
    private IPermissionRequestService permissionRequestService;

    /**
     * Submit document permission request.
     * <p>Accepts either: node_id (dst prefix) or primary key id (Long).
     * When user has no doc permission, frontend only has spaceNodeId (pk) from URL, not dst id.</p>
     */
    @PostResource(path = "/{nodeIdOrPk}/permission-requests", requiredPermission = false)
    @Operation(summary = "Submit document permission request")
    public ResponseData<PermissionRequestVo> submitRequest(
        @Parameter(description = "Node ID (dstxxx) or primary key id (number, e.g. spaceNodeId)") @PathVariable("nodeIdOrPk") String nodeIdOrPk,
        @Valid @RequestBody DocumentPermissionRequestRo ro) {
        log.info("[1822-PermApply] submit entry nodeIdOrPk={} requestedType={}", nodeIdOrPk, ro != null ? ro.getRequestedPermissionType() : null);
        String documentId = permissionRequestService.resolveToNodeId(nodeIdOrPk);
        PermissionRequestVo vo = permissionRequestService.submitRequest(documentId, ro);
        return ResponseData.success(vo);
    }
}

