   135→    @Override
   136→    public String resolveToNodeId(String nodeIdOrPk) {
   137→        if (nodeIdOrPk == null || nodeIdOrPk.isBlank()) {
   138→            return nodeIdOrPk;
   139→        }
   140→        if (nodeIdOrPk.matches("^\\d+$")) {
   141→            // 前端传的是 spaceNodeId，需通过 collabspace gRPC 解析为 dst nodeId
   142→            Long spaceNodeId = Long.parseLong(nodeIdOrPk);
   143→            String appNodeId = collabspaceGrpcClientService.getNodeIdBySpaceNodeId(spaceNodeId);
   144→            ExceptionUtil.isNotBlank(appNodeId, PermissionException.NODE_NOT_EXIST);
   145→            return appNodeId;
   146→        }
   147→        return nodeIdOrPk;
   148→    }
