   150→    @Override
   151→    @Transactional(rollbackFor = Exception.class)
   152→    public PermissionRequestVo submitRequest(String documentId, DocumentPermissionRequestRo ro) {
   153→        Long applicantUserId = SessionContext.getUserId();
   154→        ExceptionUtil.isNotNull(applicantUserId, PermissionException.NODE_ACCESS_DENIED);
   155→
   156→        // 1. Check node exists and get spaceId
   157→        String spaceId = iNodeService.checkNodeIfExist(null, documentId);
   158→        NodeEntity node = iNodeService.getByNodeId(documentId);
   159→        String documentName = node.getNodeName();
   160→
   161→        // 2. Check user is in space
   162→        Long memberId = iMemberService.getMemberIdByUserIdAndSpaceId(applicantUserId, spaceId);
   163→        ExceptionUtil.isNotNull(memberId, PermissionException.MEMBER_NOT_IN_SPACE);
   164→
   165→        // 3. Check no pending request for same document
   166→        PermissionRequestEntity pending =
   167→            baseMapper.selectPendingByDocumentAndApplicant(documentId, applicantUserId);
   168→        ExceptionUtil.isNull(pending, NotificationException.ALREADY_SUBMITTED_REQUEST);
   169→
   170→        // 4. Check user does not already have node permission
   171→        // Try fetchInternalNodeRole first (stricter, matches frontend "no view permission")
   172→        ControlRoleDict roleDict = controlTemplate.fetchInternalNodeRole(memberId, List.of(documentId));
   173→        boolean hasPermission = !roleDict.isEmpty()
   174→            && roleDict.get(documentId) != null
   175→            && roleDict.get(documentId).hasPermission(NodePermission.READ_NODE);
   176→        ExceptionUtil.isFalse(hasPermission, NotificationException.ALREADY_HAVE_PERMISSION);
   177→
   178→        // 0. 防抖：短时间内重复提交同文档只处理一次
   179→        String debounceKey = REDIS_DEBOUNCE_PREFIX + applicantUserId + ":" + documentId;
   180→        Boolean firstSubmit = redisTemplate.opsForValue().setIfAbsent(debounceKey, "1", DEBOUNCE_SECONDS, TimeUnit.SECONDS);
   181→        if (Boolean.FALSE.equals(firstSubmit)) {
   182→            log.info("[1822-PermApply] debounce applicantUserId={} documentId={}", applicantUserId, documentId);
   183→            throw new BusinessException(NotificationException.ALREADY_SUBMITTED_REQUEST);
   184→        }
   185→
   186→        // 5. Create permission request
   187→        String requestId = REQUEST_ID_PREFIX + IdWorker.getId();
   188→        PermissionRequestEntity entity = PermissionRequestEntity.builder()
   189→            .id(requestId)
   190→            .applicantUserId(applicantUserId)
   191→            .documentId(documentId)
   192→            .spaceId(spaceId)
   193→            .requestedPermissionType(ro.getRequestedPermissionType())
   194→            .status(STATUS_PENDING)
   195→            .createdAt(LocalDateTime.now())
   196→            .updatedAt(LocalDateTime.now())
   197→            .build();
   198→
   199→        boolean flag = SqlHelper.retBool(baseMapper.insert(entity));
   200→        if (!flag) {
   201→            log.error("[1822-PermApply] ERROR CREATE insert failed applicantUserId={} documentId={} spaceId={}", applicantUserId, documentId, spaceId);
   202→            ExceptionUtil.isTrue(false, DatabaseException.INSERT_ERROR);
   203→        }
   204→        log.info("[1822-PermApply] CREATE request requestId={} applicantUserId={} documentId={} spaceId={} requestedType={}",
   205→            requestId, applicantUserId, documentId, spaceId, ro.getRequestedPermissionType());
   206→
   207→        // 6. Notify space admins & applicant (async)
   208→        SpaceEntity space = iSpaceService.getBySpaceId(spaceId);
   209→        String applicantNickName = iMemberService.getMemberNameByUserIdAndSpaceId(applicantUserId, spaceId);
   210→        if (applicantNickName == null) {
   211→            applicantNickName = "";
   212→        }
   213→        String finalDocumentName = documentName;
   214→        String finalApplicantNickName = applicantNickName;
   215→        String spaceName = space.getName() != null ? space.getName() : "";
   216→        TaskManager.me().execute(() -> {
   217→            notifyAdmins(entity, finalDocumentName, finalApplicantNickName, spaceName);
   218→            notifyApplicant(entity, finalDocumentName, spaceName);
   219→        });
   220→
   221→        return buildVo(entity, documentName, space.getName());
   222→    }
