   224→    /**
   225→     * 通知所有对此文档有管理权限的用户（空间站管理员 + 文档节点管理员）.
   226→     */
   227→    private void notifyAdmins(PermissionRequestEntity request, String documentName, String applicantNickName, String spaceName) {
   228→        try {
   229→            List<com.apitable.workspace.vo.NodeRoleMemberVo> nodeRoleMembers =
   230→                iNodeRoleService.getNodeRoleMembers(request.getSpaceId(), request.getDocumentId());
   231→            List<Long> managerMemberIds = nodeRoleMembers.stream()
   232→                .filter(m -> com.apitable.control.infrastructure.role.RoleConstants.Node.MANAGER.equals(m.getRole())
   233→                    || Boolean.TRUE.equals(m.getIsWorkbenchAdmin()) || Boolean.TRUE.equals(m.getIsAdmin()))
   234→                .map(com.apitable.workspace.vo.NodeRoleMemberVo::getMemberId)
   235→                .distinct()
   236→                .collect(Collectors.toList());
   237→            if (CollUtil.isEmpty(managerMemberIds)) {
   238→                log.warn("[1822-PermApply] notifyAdmins no managers documentId={}", request.getDocumentId());
   239→                return;
   240→            }
   241→
   242→            List<Long> adminUserIds = notificationFactory.getMemberUserId(managerMemberIds, request.getSpaceId());
   243→            if (CollUtil.isEmpty(adminUserIds)) {
   244→                log.warn("[1822-PermApply] notifyAdmins no adminUserIds requestId={} spaceId={}", request.getId(), request.getSpaceId());
   245→                return;
   246→            }
   247→            log.info("[1822-PermApply] notifyAdmins requestId={} documentId={} approverCount={}", request.getId(), request.getDocumentId(), adminUserIds.size());
   248→
   249→            Map<String, Object> extras = new HashMap<>();
   250→            extras.put("requestId", request.getId());
   251→            extras.put("spaceName", spaceName);
   252→            extras.put("applicantUserId", String.valueOf(request.getApplicantUserId()));
   253→            extras.put("applicantNickName", applicantNickName);
   254→            extras.put("documentId", request.getDocumentId());
   255→            extras.put("documentName", documentName);
   256→            extras.put("requestedPermissionType", request.getRequestedPermissionType());
   257→            extras.put("status", request.getStatus());
   258→
   259→            NotificationCreateRo ro = new NotificationCreateRo();
   260→            ro.setTemplateId(NotificationTemplateId.DOCUMENT_PERMISSION_REQUEST.getValue());
   261→            ro.setFromUserId(String.valueOf(request.getApplicantUserId()));
   262→            ro.setToUserId(adminUserIds.stream().map(String::valueOf).collect(Collectors.toList()));
   263→            ro.setNodeId(request.getDocumentId());
   264→            ro.setSpaceId(request.getSpaceId());
   265→            ro.setBody(JSONUtil.createObj().set(NotificationConstants.BODY_EXTRAS, extras));
   266→            ro.setSendKnockNotification(true);
   267→
   268→            playerNotificationService.createNotify(ro);
   269→        } catch (Exception e) {
   270→            log.error("[1822-PermApply] ERROR notifyAdmins requestId={} error={}", request.getId(), e.getMessage(), e);
   271→        }
   272→    }
