   350→    @Override
   351→    @Transactional(rollbackFor = Exception.class)
   352→    public void approve(Long notificationId, Long approverUserId) {
   353→        PermissionRequestEntity request = validateAndGetRequest(notificationId, approverUserId);
   354→        // 获取文档名称
   355→        NodeEntity node = iNodeService.getByNodeId(request.getDocumentId());
   356→        String documentName = node != null ? node.getNodeName() : "";
   357→        String approverNickName = iMemberService.getMemberNameByUserIdAndSpaceId(approverUserId, request.getSpaceId());
   358→        if (approverNickName == null) {
   359→            approverNickName = "";
   360→        }
   361→        final String finalApproverNickName = approverNickName;
   362→        // Add node role for applicant
   363→        String nodeRole = mapPermissionTypeToNodeRole(request.getRequestedPermissionType());
   364→        Long applicantMemberId = iMemberService.getMemberIdByUserIdAndSpaceId(request.getApplicantUserId(), request.getSpaceId());
   365→        ExceptionUtil.isNotNull(applicantMemberId, PermissionException.MEMBER_NOT_IN_SPACE);
   366→        Long unitId = iUnitService.getUnitIdByRefId(applicantMemberId);
   367→        ExceptionUtil.isNotNull(unitId, NotificationException.APPLICANT_UNIT_NOT_FOUND);
   368→        iNodeRoleService.addNodeRole(approverUserId, request.getDocumentId(), nodeRole, Collections.singletonList(unitId));
   369→
   370→        // 同步权限到 collabspace，让 spaceNodeInfo 放行
   371→        Long spaceNodeId = collabspaceGrpcClientService.getSpaceNodeIdByNodeId(request.getDocumentId());
   372→        if (spaceNodeId != null) {
   373→            collabspaceGrpcClientService.grantNodePermission(
   374→                request.getApplicantUserId(),
   375→                request.getSpaceId(),
   376→                spaceNodeId,
   377→                nodeRole,
   378→                Collections.singletonList(unitId)
   379→            );
   380→        } else {
   381→            log.warn("[1822-PermApply] approve sync skipped spaceNodeId=null documentId={}", request.getDocumentId());
   382→        }
   383→
   384→        // Update PermissionRequest
   385→        baseMapper.updateStatusById(request.getId(), STATUS_APPROVED, approverUserId);
   386→
   387→        // 更新通知 body 的 extras，使列表接口返回正确的 status（前端据此显示「已同意」）
   388→        updateNotificationExtras(notificationId, STATUS_APPROVED, approverUserId, finalApproverNickName);
   389→
   390→        // Notify applicant
   391→        TaskManager.me().execute(() -> NotificationManager.me().playerNotify(
   392→            NotificationTemplateId.PERMISSION_APPROVED,
   393→            Collections.singletonList(request.getApplicantUserId()),
   394→            approverUserId,
   395→            request.getSpaceId(),
   396→            Map.of(
   397→                "requestId", request.getId(),
   398→                "documentId", request.getDocumentId(),
   399→                "documentName", documentName,
   400→                "status", STATUS_APPROVED,
   401→                "approverUserId", String.valueOf(approverUserId),
   402→                "approverNickName", finalApproverNickName
   403→            )));
   404→
   405→        // Mark notification as read
   406→        playerNotificationService.setNotificationIsRead(new String[]{String.valueOf(notificationId)}, 0);
   407→        log.info("[1822-PermApply] APPROVE requestId={} approverUserId={} applicantUserId={} documentId={} nodeRole={}",
   408→            request.getId(), approverUserId, request.getApplicantUserId(), request.getDocumentId(), nodeRole);
   409→    }
