   461→    private PermissionRequestEntity validateAndGetRequest(Long notificationId, Long approverUserId) {
   462→        String requestId = getRequestIdFromNotification(notificationId, approverUserId);
   463→        if (requestId == null || requestId.isBlank()) {
   464→            log.warn("[1822-PermApply] validate fail notificationInvalid notificationId={} approverUserId={}", notificationId, approverUserId);
   465→            ExceptionUtil.isNotBlank(requestId, NotificationException.NOTIFICATION_NOT_VALID);
   466→        }
   467→        PermissionRequestEntity request = baseMapper.selectById(requestId);
   468→        if (request == null) {
   469→            log.warn("[1822-PermApply] validate fail requestNotFound requestId={} notificationId={}", requestId, notificationId);
   470→            ExceptionUtil.isNotNull(request, NotificationException.PERMISSION_REQUEST_NOT_FOUND);
   471→        }
   472→        if (!STATUS_PENDING.equals(request.getStatus())) {
   473→            log.warn("[1822-PermApply] validate fail alreadyProcessed requestId={} status={}", request.getId(), request.getStatus());
   474→            ExceptionUtil.isTrue(false, NotificationException.REQUEST_ALREADY_PROCESSED);
   475→        }
   476→        validateApproverIsAdmin(approverUserId, request.getSpaceId());
   477→        return request;
   478→    }
