   495→     * 更新审批通知的 notify_body.extras，使列表接口返回正确的 status（前端据此区分已同意/已拒绝/已忽略）
   496→     */
   497→    private void updateNotificationExtras(Long notificationId, String status, Long approverUserId, String approverNickName) {
   498→        try {
   499→            String bodyStr = playerNotificationMapper.selectNotifyBodyById(notificationId);
   500→            if (bodyStr == null || bodyStr.isBlank()) return;
   501→            JSONObject body = JSONUtil.parseObj(bodyStr);
   502→            JSONObject extras = body.getJSONObject(NotificationConstants.BODY_EXTRAS);
   503→            if (extras == null) extras = new JSONObject();
   504→            extras.set("status", status);
   505→            extras.set("approverUserId", String.valueOf(approverUserId));
   506→            extras.set("approverNickName", approverNickName != null ? approverNickName : "");
   507→            body.set(NotificationConstants.BODY_EXTRAS, extras);
   508→            playerNotificationMapper.updateNotifyBodyById(notificationId, body.toString());
   509→        } catch (Exception e) {
   510→            log.warn("[1822-PermApply] updateNotificationExtras failed notificationId={} status={} error={}", notificationId, status, e.getMessage(), e);
   511→        }
   512→    }
   513→
   514→    private String getRequestIdFromNotification(Long notificationId, Long approverUserId) {
   515→        com.apitable.player.entity.PlayerNotificationEntity notification =
   516→            playerNotificationService.getById(notificationId);
   517→        if (notification == null || !approverUserId.equals(notification.getToUser())) {
   518→            return null;
   519→        }
   520→        if (!DOCUMENT_PERMISSION_REQUEST.equals(notification.getTemplateId())) {
   521→            return null;
   522→        }
   523→        String body = notification.getNotifyBody();
   524→        if (body == null) {
   525→            return null;
   526→        }
   527→        JSONObject json = JSONUtil.parseObj(body);
   528→        JSONObject extras = json.getJSONObject(NotificationConstants.BODY_EXTRAS);
   529→        if (extras == null) {
   530→            return null;
   531→        }
   532→        return extras.getStr("requestId");
