   535→    private void validateApproverIsAdmin(Long approverUserId, String spaceId) {
   536→        var userSpace = userSpaceCacheService.getUserSpace(approverUserId, spaceId);
   537→        ExceptionUtil.isNotNull(userSpace, SpaceException.NOT_IN_SPACE);
   538→        ExceptionUtil.isTrue(CollUtil.contains(userSpace.getResourceCodes(), "INVITE_MEMBER"),
   539→            SpacePermissionException.INSUFFICIENT_PERMISSIONS);
   540→    }
