service CollabspaceServingService {

  rpc GetNodeRoles (GetNodeRolesRequest) returns (GetNodeRolesResult);

  rpc FetchInternalNodeRoles (FetchNodeRolesRequest) returns (FetchNodeRolesResult);

  rpc FetchNodeRoles (FetchNodeRolesRequest) returns (FetchNodeRolesResult);

  rpc FetchNodeTreeNodeRoles (FetchNodeRolesRequest) returns (FetchNodeRolesResult);

  rpc AppTeamsBindQuery(AppTeamsBindQueryRequest) returns (AppTeamsBindsResult);

  rpc AppTeamUnbind(AppTeamUnbindRequest) returns (grpc.common.BasicResult);

  rpc NodeInfoUpdate (NodeInfoUpdateRequest) returns (grpc.common.BasicResult);

  rpc LogMethod (LogMethodRequest) returns (grpc.common.BasicResult);

  rpc GetSpaceNodeIdByNodeId (GetSpaceNodeIdByNodeIdRequest) returns (GetSpaceNodeIdByNodeIdResult);

  rpc GetNodeIdBySpaceNodeId (GetNodeIdBySpaceNodeIdRequest) returns (GetNodeIdBySpaceNodeIdResult);

  // Grant node permission for a user/unit on given node.
  rpc GrantNodePermission (GrantNodePermissionRequest) returns (grpc.common.BasicResult);
}

message GetNodeRolesRequest {
  int64 userId = 1;
  string spaceId = 2;
  string nodeId = 3;
}

message GetNodeRolesResult {
  NodeCollaboratorsVo data = 1;
}

message NodeCollaboratorsVo {
  bool extend = 1;
  repeated UnitMemberVo admins = 2;
  UnitMemberVo owner = 3;
  UnitMemberVo self = 4;
  repeated NodeRoleUnit roleUnits = 5;
  string extendNodeName = 6;
  bool belongRootFolder = 7;
}

message FetchNodeRolesRequest {
  int64 userId = 1;
  repeated string nodeIds = 2;
}

message FetchNodeRolesResult {
  map<string, NodeRoleInfo> roleDict = 1;
}

message NodeRoleInfo {
  string roleTag = 1;
  bool ghostNode = 2;
}

message AppTeamsBindQueryRequest {
  string appSpaceId = 1;
  int32 appType=2;
  repeated int64 appTeamIds = 3;
}

message AppTeamsBindsResult {
  repeated AppTeamBindResult bindInfos=1;
}

message AppTeamBindResult {
  int64 teamId=1;
  repeated AioTeamInfo aioTeamInfos=2;
}

message AioTeamInfo {
  int64 aioTeamId=1;
  string aioTeamName=2;
  int64 aioProjectId=3;
  string aioProjectName=4;
}

message AppTeamUnbindRequest {
  string appSpaceId = 1;
  string appTeamId = 2;
}

message NodeInfoUpdateRequest{
  string appNodeId = 1;
  string appSpaceId = 2;
  string nodeName = 3;
  int64 userId = 4;
  int32 appType = 5;
  int32 nodeType = 6;
}

message LogMethodRequest {
  string traceId = 1;
  string spaceId = 2;
  string className = 3;
  string methodName = 4;
  int64 userId = 5;
}

message GetSpaceNodeIdByNodeIdRequest {
  string appNodeId = 1;
}

message GetSpaceNodeIdByNodeIdResult {
  int64 spaceNodeId = 1;
}

message GrantNodePermissionRequest {
  int64 userId = 1;
  string spaceId = 2;
  int64 spaceNodeId = 3;
  string role = 4;
  repeated int64 unitIds = 5;
}

message GetNodeIdBySpaceNodeIdRequest {
  int64 spaceNodeId = 1;
}

message GetNodeIdBySpaceNodeIdResult {
  string appNodeId = 1;
}

