import lombok.extern.slf4j.Slf4j;
import net.devh.boot.grpc.client.inject.GrpcClient;

import org.apache.commons.collections4.CollectionUtils;
import org.springframework.beans.factory.annotation.Qualifier;
import org.springframework.stereotype.Service;

import java.util.ArrayList;
import java.util.List;
import java.util.Map;

@Service
@Slf4j
public class CollabspaceGrpcClientServiceImpl implements ICollabspaceGrpcClientService {

    @GrpcClient("collabspace-grpc-server")
    private CollabspaceServingServiceBlockingStub collabspaceStub;

    @Resource
    @Qualifier("grpcProtobufMapperImpl")
    private GrpcProtobufMapper grpcMapper;

    @Override
    public NodeCollaboratorsVo getNodeRoles(Long userId, String spaceId, String nodeId) {
        try {
            GetNodeRolesRequest request = GetNodeRolesRequest.newBuilder()
                    .setUserId(userId)
                    .setSpaceId(spaceId)
                    .setNodeId(nodeId)
                    .build();

            GetNodeRolesResult result = collabspaceStub.getNodeRoles(request);

            if (result.hasData()) {
                return grpcMapper.toNodeCollaboratorsVo(result.getData());
            }

            return null;
        } catch (StatusRuntimeException e) {
            log.error("grpc getNodeRoles error", e);
            return null; // todo 统一抛自定义异常
        }
    }

    @Override
    public ControlRoleDict fetchInternalNodeRole(Long userId, List<String> nodeIds) {
        if (userId == null||CollectionUtils.isEmpty(nodeIds)) {
            log.warn("fetchInternalNodeRole: userId is null or nodeId is empty, userId: {}, nodeIds: {}", userId, nodeIds);
            return ControlRoleDict.create();
        }
        try {
            FetchNodeRolesRequest request = FetchNodeRolesRequest.newBuilder()
                    .setUserId(userId)
                    .addAllNodeIds(nodeIds)
                    .build();

            FetchNodeRolesResult result = collabspaceStub.fetchInternalNodeRoles(request);

            ControlRoleDict roleDict = ControlRoleDict.create();
            Map<String, NodeRoleInfo> resultRoleDict = result.getRoleDictMap();

            for (Map.Entry<String, NodeRoleInfo> entry : resultRoleDict.entrySet()) {
                String nodeId = entry.getKey();
                NodeRoleInfo roleInfo = entry.getValue();

                String roleTag = roleInfo.getRoleTag();

                ControlRole role;
                if (!roleTag.isEmpty()) {
                    try {
                        role = ControlRoleManager.parseNodeRole(roleTag);
                    } catch (Exception e) {
                        log.error("Failed to parse role tag: {}", roleTag, e);
                        role = new NodeRole();
                    }
                } else {
                    role = new NodeRole();
                }

                if (role instanceof NodeRole) {
                    ((NodeRole) role).setGhostNode(roleInfo.getGhostNode());
                }

                roleDict.put(nodeId, role);
            }

            return roleDict;
        } catch (StatusRuntimeException e) {
            log.error("grpc fetchInternalNodeRoles error", e);
            return ControlRoleDict.create();// todo throw?
        }
    }

