    @Override
    public List<TeamAioBindInfo> queryAppTeamsBind(List<Long> teamIds, String spaceId) {
        try {
            AppTeamsBindQueryRequest request = AppTeamsBindQueryRequest.newBuilder().
                    setAppSpaceId(spaceId).setAppType(1).addAllAppTeamIds(teamIds).build();


            AppTeamsBindsResult appTeamsBindsResult = collabspaceStub.appTeamsBindQuery(request);
            List<TeamAioBindInfo> result=new ArrayList<>();

            List<AppTeamBindResult> bindInfosList = appTeamsBindsResult.getBindInfosList();
            if(CollectionUtils.isNotEmpty(bindInfosList)){
                bindInfosList.forEach(bi->{

                    TeamAioBindInfo teamAioBindInfo = new TeamAioBindInfo();
                    teamAioBindInfo.setTeamId(bi.getTeamId());

                    List<AioTeamInfo> aioTeamInfosList = bi.getAioTeamInfosList();
                    if(CollectionUtils.isNotEmpty(aioTeamInfosList)){
                        List<AioTeamBindInfo> aioTeamInfos=new ArrayList<>();
                        aioTeamInfosList.forEach(info->{
                            aioTeamInfos.add(AioTeamBindInfo.builder().
                                    aioTeamId(info.getAioTeamId()).
                                    aioTeamName(info.getAioTeamName()).
                                    aioProjectIdName(info.getAioProjectName()).
                                    aioProjectId(info.getAioProjectId()).build());
                        });
                        teamAioBindInfo.setAioTeamInfos(aioTeamInfos);
                    }

                    result.add(teamAioBindInfo);
                });
            }

            return result;
