            return (appNodeId == null || appNodeId.isEmpty()) ? null : appNodeId;
        } catch (StatusRuntimeException e) {
            log.error("[1822-PermApply] ERROR getNodeIdBySpaceNodeId spaceNodeId={} error={}", spaceNodeId, e.getMessage(), e);
            return null;
        }
    }

    @Override
    public void grantNodePermission(Long userId, String spaceId, Long spaceNodeId, String role, List<Long> unitIds) {
        if (userId == null || spaceId == null || spaceNodeId == null || unitIds == null || unitIds.isEmpty()) {
            log.warn("[1822-PermApply] grantNodePermission invalid userId={} spaceId={} spaceNodeId={}", userId, spaceId, spaceNodeId);
            return;
        }
        try {
            GrantNodePermissionRequest request = GrantNodePermissionRequest.newBuilder()
                    .setUserId(userId)
                    .setSpaceId(spaceId)
                    .setSpaceNodeId(spaceNodeId)
                    .setRole(role)
                    .addAllUnitIds(unitIds)
                    .build();
            BasicResult result = collabspaceStub.grantNodePermission(request);
            if (!result.getSuccess()) {
                log.error("[1822-PermApply] ERROR grantNodePermission failed code={} msg={}", result.getCode(), result.getMessage());
            } else {
                log.info("[1822-PermApply] grantNodePermission success userId={} spaceId={} spaceNodeId={} role={}", userId, spaceId, spaceNodeId, role);
            }
        } catch (StatusRuntimeException e) {
            log.error("[1822-PermApply] ERROR grantNodePermission userId={} spaceId={} spaceNodeId={} error={}", userId, spaceId, spaceNodeId, e.getMessage(), e);
        }
    }

    @Override
    public void logMethod(String traceId, String spaceId, String className, String methodName, Long userId) {
        try {
            LogMethodRequest request = LogMethodRequest.newBuilder()
                    .setTraceId(traceId)
                    .setSpaceId(spaceId)
                    .setClassName(className)
                    .setMethodName(methodName)
                    .setUserId(userId)
                    .build();

            BasicResult basicResult = collabspaceStub.logMethod(request);
        } catch (StatusRuntimeException e) {
            log.error("grpc logMethod error", e);
        }
    }

}

