   234→                                .build();
   235→
   236→                        resultBuilder.putRoleDict(appSpaceNodeId, roleInfo);
   237→                    } catch (Exception e) {
   238→                        log.error("Error converting role for nodeId: {}, error: {}", appSpaceNodeId, e.getMessage());
