    @Override
    public void createSpaceNodeMigrationTask(CreateSpaceNodeMigrationTaskRequest request, StreamObserver<CreateSpaceNodeMigrationTaskResult> responseObserver) {
        log.info("createSpaceNodeMigrationTask: email={}, targetSpaceId={}, sourceSpaceId={}, treeSize={}",
                request.getEmail(), request.getTargetSpaceId(), request.getSourceSpaceId(), request.getSpaceNodeTreeCount());

        try {
            List<TreeNode<SpaceNodeVo>> spaceNodeTree = grpcMapper.toTreeNodes(request.getSpaceNodeTreeList());
            List<SpaceAppRelVo> appRelVos = grpcMapper.toSpaceAppRelVos(request.getSourceSpaceAppsList());
            String taskId = spaceNodeMigrationUpdateManager.acceptMigrationTask(spaceNodeTree, request.getEmail(), request.getTargetSpaceId(), request.getSourceSpaceId(), appRelVos, MigrationTypeEnum.CROSS_SERVER.getValue(), true);

            log.info("createSpaceNodeMigrationTask success: taskId={}", taskId);

            CreateSpaceNodeMigrationTaskResult result = CreateSpaceNodeMigrationTaskResult.newBuilder()
                    .setTaskId(taskId)
                    .build();

            responseObserver.onNext(result);
            responseObserver.onCompleted();
        } catch (Exception e) {
            log.error("createSpaceNodeMigrationTask error", e);
            responseObserver.onError(e);
        }
    }

    @Override
    public void getSpaceNodeMigrationTask(GetSpaceNodeMigrationTaskRequest request, StreamObserver<GetSpaceNodeMigrationTaskResult> responseObserver) {
        log.info("getSpaceNodeMigrationTask: taskId={}", request.getTaskId());
        try {
            SpaceNodeMigrationTaskEntity entity = spaceNodeMigrationTaskService.getByTaskId(request.getTaskId());
            GetSpaceNodeMigrationTaskResult result = GetSpaceNodeMigrationTaskResult.newBuilder()
                    .setTaskId(entity.getTaskId())
                    .setEmail(entity.getEmail() != null ? entity.getEmail() : "")
                    .setTargetSpaceId(entity.getTargetSpaceId() != null ? entity.getTargetSpaceId() : "")
                    .setSourceSpaceId(entity.getSourceSpaceId() != null ? entity.getSourceSpaceId() : "")
                    .setErrorMessage(entity.getErrorMessage() != null ? entity.getErrorMessage() : "")
                    .setStatus(entity.getStatus())
                    .build();

            responseObserver.onNext(result);
            responseObserver.onCompleted();
        } catch (Exception e) {
            log.error("getSpaceNodeMigrationTask error: taskId={}", request.getTaskId(), e);
            responseObserver.onError(e);
        }
    }

    @Override
    public void listManagedSpaceForMigration(ListManagedSpaceForMigrationRequest request, StreamObserver<ListManagedSpaceForMigrationResult> responseObserver) {
        log.info("listManagedSpaceForMigration: email={}", request.getEmail());
        try {
            UserSimpleInfoVo user = apitableGrpcClientService.getUserByEmail(request.getEmail());
            if (user == null) {
                log.error("User not found with email: {}", request.getEmail());
                responseObserver.onNext(ListManagedSpaceForMigrationResult.newBuilder().build());
                responseObserver.onCompleted();
                return;
            }
            Long userId = user.getId();
            List<SpaceEntity> spaceEntities = spaceQueryManager.getMemberManagedSpace(userId);

            List<SpaceInfo> spaceInfos = spaceEntities.stream()
                    .map(entity -> SpaceInfo.newBuilder()
                            .setSpaceId(entity.getSpaceId())
                            .setName(entity.getName())
                            .setOwner(entity.getOwner())
                            .build())
                    .collect(Collectors.toList());

            ListManagedSpaceForMigrationResult result = ListManagedSpaceForMigrationResult.newBuilder()
                    .addAllSpaces(spaceInfos)
                    .build();

            responseObserver.onNext(result);
            responseObserver.onCompleted();
        } catch (Exception e) {
            log.error("listManagedSpaceForMigration error: email={}", request.getEmail(), e);
            responseObserver.onError(e);
        }
    }

    @Override
    public void logMethod(LogMethodRequest request, StreamObserver<BasicResult> responseObserver) {
        try {
            MethodLogEntity entity = MethodLogEntity.builder()
                    .traceId(request.getTraceId())
                    .spaceId(request.getSpaceId())
                    .methodName(request.getMethodName())
                    .className(request.getClassName())
                    .createdBy(request.getUserId())
                    .build();
            methodLogService.save(entity);

            BasicResult result = BasicResult.newBuilder()
                    .setCode(DEFAULT_SUCCESS_CODE)
                    .setMessage(DEFAULT_SUCCESS_MESSAGE)
                    .setSuccess(true)
                    .build();
            responseObserver.onNext(result);
            responseObserver.onCompleted();
        } catch (Exception e) {
            log.error("logMethod error", e);
            responseObserver.onError(e);
        }
    }

    @Override
    public void getSpaceNodeIdByNodeId(GetSpaceNodeIdByNodeIdRequest request, StreamObserver<GetSpaceNodeIdByNodeIdResult> responseObserver) {
        try {
            String appNodeId = request.getAppNodeId();
            List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listByAppSpaceNodeIds(List.of(appNodeId));

            long spaceNodeId = 0L;
            if (CollectionUtils.isNotEmpty(spaceNodeEntities)) {
                spaceNodeId = spaceNodeEntities.getFirst().getId();
            }

            GetSpaceNodeIdByNodeIdResult result = GetSpaceNodeIdByNodeIdResult.newBuilder()
                    .setSpaceNodeId(spaceNodeId)
                    .build();

            responseObserver.onNext(result);
            responseObserver.onCompleted();
        } catch (Exception e) {
            log.error("[1822-PermApply] ERROR getSpaceNodeIdByNodeId appNodeId={} error={}", request.getAppNodeId(), e.getMessage(), e);
            responseObserver.onError(e);
        }
    }

    @Override
    public void grantNodePermission(GrantNodePermissionRequest request,
                                    StreamObserver<BasicResult> responseObserver) {
        Long userId = request.getUserId();
        String spaceId = request.getSpaceId();
        Long spaceNodeId = request.getSpaceNodeId();
        String role = request.getRole();
        List<Long> unitIds = request.getUnitIdsList();
        try {
            nodeRoleUpdateManager.addNodeRole(userId, spaceId, spaceNodeId, role, unitIds);
            log.info("[1822-PermApply] grantNodePermission success userId={} spaceId={} spaceNodeId={} role={}", userId, spaceId, spaceNodeId, role);
            BasicResult result = BasicResult.newBuilder()
                    .setCode(DEFAULT_SUCCESS_CODE)
                    .setMessage(DEFAULT_SUCCESS_MESSAGE)
                    .setSuccess(true)
                    .build();
            responseObserver.onNext(result);
            responseObserver.onCompleted();
        } catch (Exception e) {
            log.error("[1822-PermApply] ERROR grantNodePermission userId={} spaceId={} spaceNodeId={} error={}", userId, spaceId, spaceNodeId, e.getMessage(), e);
            responseObserver.onError(e);
        }
    }

    @Override
    public void getNodeIdBySpaceNodeId(GetNodeIdBySpaceNodeIdRequest request, StreamObserver<GetNodeIdBySpaceNodeIdResult> responseObserver) {
        try {
            long spaceNodeId = request.getSpaceNodeId();
            SpaceNodeEntity entity = spaceNodeService.getById(spaceNodeId);
            String appNodeId = entity != null ? entity.getAppSpaceNodeId() : "";
            GetNodeIdBySpaceNodeIdResult result = GetNodeIdBySpaceNodeIdResult.newBuilder()
                    .setAppNodeId(appNodeId != null ? appNodeId : "")
                    .build();
            responseObserver.onNext(result);
            responseObserver.onCompleted();
        } catch (Exception e) {
            log.error("[1822-PermApply] ERROR getNodeIdBySpaceNodeId spaceNodeId={} error={}", request.getSpaceNodeId(), e.getMessage(), e);
            responseObserver.onError(e);
        }
    }

    @Override
    public  void getExactAnnouncement(GetExactAnnouncementRequest request,
                                                          StreamObserver<GetExactAnnouncementResult> responseObserver){
        try {
            List<GetListAnnouncementVo> announcementVos = announcementService.getAnnounceList(AnnouncementStatus.WAITING.getCode());
            List<String> list = new ArrayList<>();
            // 根据userid补充email
            List<Long> userIds = announcementVos.stream().map(GetListAnnouncementVo::getCreatorId).toList();
            if (!userIds.isEmpty()) {
                List<UserSimpleInfoVo> userSimpleInfoVoList = apitableGrpcClientService.getUserByIds(userIds);
                log.info("getExactAnnouncement: userIds={}", userSimpleInfoVoList.stream().map(UserSimpleInfoVo::getEmail).toList());
                userSimpleInfoVoList = userSimpleInfoVoList.stream().filter(o -> o.getEmail() != null).toList();
                Map<Long, String> userEmailMap = userSimpleInfoVoList.stream()
                        .collect(Collectors.toMap(
                                UserSimpleInfoVo::getId,
                                UserSimpleInfoVo::getEmail
                        ));
                announcementVos.forEach(announcement -> {
                    announcement.setCreatorEmail(userEmailMap.get(announcement.getCreatorId()));
                });
            }
            announcementVos.forEach(vo -> list.add(JSONUtil.toJsonStr(vo)));
            GetExactAnnouncementResult result = GetExactAnnouncementResult.newBuilder()
                    .addAllList(list)
                    .build();
            responseObserver.onNext(result);
            responseObserver.onCompleted();
        }
        catch (Exception e) {
            log.error("getExactAnnouncement error", e);
            responseObserver.onError(e);
        }
    }

    @Override
    public void getAnnouncementById(GetAnnouncementRequest request, StreamObserver<GetAnnouncementResult> responseObserver) {
        try {
            List<GetListAnnouncementVo> announcementVos = announcementService.getAnnouncementById(request.getAnnouncementIdListList());
            List<String> list = new ArrayList<>();
            List<Long> userIds = announcementVos.stream().map(GetListAnnouncementVo::getCreatorId).toList();
            if (!userIds.isEmpty()) {
                List<UserSimpleInfoVo> userSimpleInfoVoList = apitableGrpcClientService.getUserByIds(userIds);
                log.info("getAnnouncementById: userIds={}", userSimpleInfoVoList.stream().map(UserSimpleInfoVo::getEmail).toList());
                userSimpleInfoVoList = userSimpleInfoVoList.stream().filter(o -> o.getEmail() != null).toList();
                Map<Long, String> userEmailMap = userSimpleInfoVoList.stream()
                        .collect(Collectors.toMap(
                                UserSimpleInfoVo::getId,
                                UserSimpleInfoVo::getEmail
                        ));
                announcementVos.forEach(announcement -> {
                    announcement.setCreatorEmail(userEmailMap.get(announcement.getCreatorId()));
                });
            }
            announcementVos.forEach(vo -> list.add(JSONUtil.toJsonStr(vo)));
            GetAnnouncementResult result = GetAnnouncementResult.newBuilder()
                    .addAllList(list)
                    .build();
            responseObserver.onNext(result);
            responseObserver.onCompleted();
        }
        catch (Exception e) {
            log.error("getAnnouncementById error", e);
            responseObserver.onError(e);
        }
    }

    @Override
    public void listManagedSpaceDataSheet(
            ListManagedSpaceDataSheetRequest request,
            StreamObserver<ListManagedSpaceDataSheetResponse> responseObserver) {

        try {

            String email = request.getEmail();
            List<SpaceWithNodeVo> spaceWithNodeVos =
                    spaceNodeQueryManager.listManagedSpaceDataSheetWithEmail(email);

            // 转换为 gRPC 响应
            ListManagedSpaceDataSheetResponse response = spaceGrpcConverter.toGrpcResponse(spaceWithNodeVos);

            responseObserver.onNext(response);
            responseObserver.onCompleted();

            log.info("gRPC 服务端响应成功");

        } catch (Exception e) {
            log.error(" listManagedSpaceDataSheet gRPC 服务端处理失败", e);
            responseObserver.onError(Status.INTERNAL
                    .withDescription("服务器内部错误: " + e.getMessage())
                    .withCause(e)
                    .asRuntimeException());
        }
    }


}

