package com.yottastudios.ns.collabspace.control.entity;

import com.baomidou.mybatisplus.annotation.IdType;
import com.baomidou.mybatisplus.annotation.TableField;
import com.baomidou.mybatisplus.annotation.TableId;
import com.baomidou.mybatisplus.annotation.TableLogic;
import com.baomidou.mybatisplus.annotation.TableName;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;

import java.time.LocalDateTime;

/**
 * Document permission request entity.
 * 表名: collabspace_permission_request
 */
@Data
@NoArgsConstructor
@AllArgsConstructor
@Builder
@TableName(keepGlobalPrefix = true, value = "permission_request")
public class PermissionRequestEntity {

    @TableId(value = "id", type = IdType.INPUT)
    private String id;

    private Long applicantUserId;

    private String documentId;

    private String spaceId;

    @TableField("requested_permission_type")
    private String requestedPermissionType;

    private String status;

    @TableField("approver_user_id")
    private Long approverUserId;

    private LocalDateTime createdAt;

    private LocalDateTime updatedAt;

    @TableLogic
    @TableField("is_deleted")
    private Integer isDeleted;
}

