                    .map(SpaceNodeEntity::getId)
                    .toList();

            ControlRoleDict controlRoleDict = controlTemplate.fetchInternalNodeRole(request.getUserId(), spaceNodeIds);

            FetchNodeRolesResult.Builder resultBuilder = convertAndSetRoleDict(spaceNodeEntities, controlRoleDict);

            responseObserver.onNext(resultBuilder.build());
            responseObserver.onCompleted();
        } catch (Exception e) {
            log.error("fetchInternalNodeRoles error", e);
            responseObserver.onError(e);
        }
