    @Override
    public void getNodeRoles(GetNodeRolesRequest request, StreamObserver<GetNodeRolesResult> responseObserver) {
        log.info("getNodeRoles: userId={}, spaceId={}, nodeId={}",
                request.getUserId(), request.getSpaceId(), request.getNodeId());

        try {
            List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listByAppSpaceNodeIds(List.of(request.getNodeId()));
            Long spaceNodeId = null;
            if (CollectionUtils.isNotEmpty(spaceNodeEntities)) {
                spaceNodeId = spaceNodeEntities.getFirst().getId();
            }

            NodeCollaboratorsVo vo = nodeRoleQueryManager.getNodeRoles(
                    request.getUserId(),
                    request.getSpaceId(),
                    spaceNodeId
            );

            GetNodeRolesResult result = GetNodeRolesResult.newBuilder()
                    .setData(grpcMapper.toGrpcNodeCollaboratorsVo(vo))
                    .build();

            responseObserver.onNext(result);
            responseObserver.onCompleted();
        } catch (Exception e) {
            log.error("getNodeRoles error", e);
            responseObserver.onError(e);
        }
    }

    @Override
    public void fetchInternalNodeRoles(FetchNodeRolesRequest request, StreamObserver<FetchNodeRolesResult> responseObserver) {
        log.info("fetchInternalNodeRoles: userId={}, nodeIds={}", request.getUserId(), request.getNodeIdsList());

        try {
            List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listByAppSpaceNodeIds(request.getNodeIdsList());
            if (CollectionUtils.isEmpty(spaceNodeEntities)) {
                responseObserver.onNext(FetchNodeRolesResult.newBuilder().build());
                responseObserver.onCompleted();
                return;
            }

            List<Long> spaceNodeIds = spaceNodeEntities.stream()
                    .map(SpaceNodeEntity::getId)
                    .toList();

            ControlRoleDict controlRoleDict = controlTemplate.fetchInternalNodeRole(request.getUserId(), spaceNodeIds);

            FetchNodeRolesResult.Builder resultBuilder = convertAndSetRoleDict(spaceNodeEntities, controlRoleDict);

            responseObserver.onNext(resultBuilder.build());
            responseObserver.onCompleted();
        } catch (Exception e) {
            log.error("fetchInternalNodeRoles error", e);
            responseObserver.onError(e);
        }
    }

    @Override
    public void fetchNodeTreeNodeRoles(FetchNodeRolesRequest request, StreamObserver<FetchNodeRolesResult> responseObserver) {
        log.info("fetchNodeTreeNodeRoles: userId={}, nodeIds={}", request.getUserId(), request.getNodeIdsList());

        try {
            List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listByAppSpaceNodeIds(request.getNodeIdsList());
            if (CollectionUtils.isEmpty(spaceNodeEntities)) {
                FetchNodeRolesResult.Builder resultBuilder = FetchNodeRolesResult.newBuilder();
                // 这里和其他的fetchRoles方法不同, 由于apitable的文件夹(fodxxx)没在aio里存, 需要设置一个默认权限
                setFodDefaultRole(request, resultBuilder);
                responseObserver.onNext(resultBuilder.build());
                responseObserver.onCompleted();
                return;
            }

            List<Long> spaceNodeIds = spaceNodeEntities.stream()
                    .map(SpaceNodeEntity::getId)
                    .toList();

            ControlRoleDict controlRoleDict = controlTemplate.fetchNodeTreeNode(request.getUserId(), spaceNodeIds);

            FetchNodeRolesResult.Builder resultBuilder = convertAndSetRoleDict(spaceNodeEntities, controlRoleDict);

            // 这里和其他的fetchRoles方法不同, 由于apitable的文件夹(fodxxx)没在aio里存, 需要设置一个默认权限
            setFodDefaultRole(request, resultBuilder);

            responseObserver.onNext(resultBuilder.build());
            responseObserver.onCompleted();
        } catch (Exception e) {
            log.error("fetchNodeTreeNodeRoles error", e);
            responseObserver.onError(e);
        }
    }

    private FetchNodeRolesResult.Builder convertAndSetRoleDict(List<SpaceNodeEntity> spaceNodeEntities, ControlRoleDict controlRoleDict) {
        Map<String, String> idToAppSpaceNodeIdMap = spaceNodeEntities.stream()
                .collect(Collectors.toMap(
                        entity -> entity.getId().toString(),
                        SpaceNodeEntity::getAppSpaceNodeId
                ));

        FetchNodeRolesResult.Builder resultBuilder = FetchNodeRolesResult.newBuilder();

        controlRoleDict.entrySet().stream()
                .filter(entry -> idToAppSpaceNodeIdMap.containsKey(entry.getKey()))
                .forEach(entry -> {
                    // 替换key为appSpaceNodeId
                    String appSpaceNodeId = idToAppSpaceNodeIdMap.get(entry.getKey());
                    ControlRole controlRole = entry.getValue();

                    try {
                        String roleTag = controlRole.getRoleTag();
                        if (roleTag == null) {
                            roleTag = "";
                        }

                        // NodeRole要传下ghostNode
                        boolean isGhostNode = false;
                        if (controlRole instanceof NodeRole) {
                            isGhostNode = ((NodeRole) controlRole).isGhostNode();
                        }

                        NodeRoleInfo roleInfo = NodeRoleInfo.newBuilder()
                                .setRoleTag(roleTag)
                                .setGhostNode(isGhostNode)
                                .build();

                        resultBuilder.putRoleDict(appSpaceNodeId, roleInfo);
                    } catch (Exception e) {
                        log.error("Error converting role for nodeId: {}, error: {}", appSpaceNodeId, e.getMessage());
                        // todo: or throw?
                    }
                });
        return resultBuilder;
    }

    private void setFodDefaultRole(FetchNodeRolesRequest request, FetchNodeRolesResult.Builder resultBuilder) {
        NodeRoleInfo readerRole = NodeRoleInfo.newBuilder()
                .setRoleTag(RoleConstants.SpaceNode.MANAGER)
                .setGhostNode(false)
                .build();

        // 处理所有fod开头的node 默认设置为MANAGER(非MANAGER会导致一些功能缺失)
        for (String nodeId : request.getNodeIdsList()) {
            if (nodeId.startsWith("fod")) {
                resultBuilder.putRoleDict(nodeId, readerRole);
            }
        }
    }

    @Override
    public void fetchNodeRoles(FetchNodeRolesRequest request, StreamObserver<FetchNodeRolesResult> responseObserver) {
        log.info("fetchNodeRoles: userId={}, nodeIds={}", request.getUserId(), request.getNodeIdsList());

        try {
            List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listByAppSpaceNodeIds(request.getNodeIdsList());
            if (CollectionUtils.isEmpty(spaceNodeEntities)) {
                FetchNodeRolesResult.Builder resultBuilder = FetchNodeRolesResult.newBuilder();

                setFodDefaultRole(request, resultBuilder); // todo 这样改可能导致权限多分配了一点, 需要换个方法处理
                responseObserver.onNext(resultBuilder.build());
                responseObserver.onCompleted();
                return;
            }

            List<Long> spaceNodeIds = spaceNodeEntities.stream()
                    .map(SpaceNodeEntity::getId)
                    .toList();

            ControlRoleDict controlRoleDict = controlTemplate.fetchSpaceNodeRole(request.getUserId(), spaceNodeIds);

            FetchNodeRolesResult.Builder resultBuilder = convertAndSetRoleDict(spaceNodeEntities, controlRoleDict);

            responseObserver.onNext(resultBuilder.build());
            responseObserver.onCompleted();
        } catch (Exception e) {
            log.error("fetchNodeRoles error", e);
            responseObserver.onError(e);
        }
    }

    @Override
    public void appTeamsBindQuery(AppTeamsBindQueryRequest request, StreamObserver<AppTeamsBindsResult> responseObserver) {
        log.info("appTeamsBindQuery: appSpaceId={}, appType={}, appTeamIds={} ",
                request.getAppSpaceId(), request.getAppType(),JSONUtil.toJsonStr(request.getAppTeamIdsList()));

        try {

            String appSpaceId = request.getAppSpaceId();
            int appType = request.getAppType();
            List<Long> appTeamIdsList = request.getAppTeamIdsList();

            String spaceId = spaceAppRelService.getByAppSpaceId(appSpaceId).getSpaceId();

            List<AppTeamQueryRo> queryRos=new ArrayList<>();
            appTeamIdsList.forEach(ti->{
                queryRos.add(AppTeamQueryRo.builder().appTeamId(String.valueOf(ti)).appType(appType).spaceId(spaceId).build());
            });

            List<AppTeamBindInfoQueryVo> appTeamBindInfoQueryVos = userTeamQueryManager.queryBindInfoByAppTeams(new AppTeamBindInfoQueryRo(queryRos), null);

            ArrayList<AppTeamBindResult> teamsBindList = new ArrayList<>();

            if(CollectionUtils.isNotEmpty(appTeamBindInfoQueryVos)){
                appTeamBindInfoQueryVos.forEach(bindInfo->{
                    ArrayList<AioTeamInfo> aioTeamInfos = new ArrayList<>();
                    List<TeamInfoWithProjectVo> aioTeams = bindInfo.getTeams();
                    if(CollectionUtils.isNotEmpty(aioTeams)){
                        aioTeams.forEach(at->{
                            aioTeamInfos.add(AioTeamInfo.newBuilder().
                                    setAioTeamId(at.getId()).
                                    setAioTeamName(null!=at.getName()?at.getName():"").
                                    setAioProjectId(at.getProjectId()).
                                    setAioProjectName(null!=at.getProjectName()?at.getProjectName():"").build());
                        });
                    }
                    teamsBindList.add(
                            AppTeamBindResult.newBuilder().setTeamId(Long.parseLong(bindInfo.getAppTeamId())).addAllAioTeamInfos(aioTeamInfos).build());
                });

            }

            AppTeamsBindsResult result = AppTeamsBindsResult.newBuilder()
                    .addAllBindInfos(teamsBindList)
                    .build();

            responseObserver.onNext(result);
            responseObserver.onCompleted();
        } catch (Exception e) {
            log.error("getNodeRoles error", e);
            responseObserver.onError(e);
        }
    }

