/**
 * Permission request service implementation.
 */
@Slf4j
@Service
public class PermissionRequestServiceImpl extends ServiceImpl<PermissionRequestMapper, PermissionRequestEntity>
    implements IPermissionRequestService {

    private static final String STATUS_PENDING = "PENDING";
    private static final String REQUEST_ID_PREFIX = "req_";

    @Resource
    private INodeService iNodeService;

    @Resource
    private ISpaceService iSpaceService;

    @Resource
    private IMemberService iMemberService;

    @Resource
    private ISpaceRoleService iSpaceRoleService;

    @Resource
    private IPlayerNotificationService playerNotificationService;

    @Resource
    private INotificationFactory notificationFactory;

    @Resource
    private ControlTemplate controlTemplate;

    @Resource
    private PlayerNotificationMapper playerNotificationMapper;

    @Resource
    private INodeRoleService iNodeRoleService;

    @Resource
    private IUnitService iUnitService;

    @Resource
    private UserSpaceCacheService userSpaceCacheService;

    @Resource
    private ICollabspaceGrpcClientService collabspaceGrpcClientService;

    @Resource
    private RedisTemplate<String, Object> redisTemplate;

    private static final String REDIS_DEBOUNCE_PREFIX = "permission_apply_debounce:";
    private static final long DEBOUNCE_SECONDS = 10;

    private static final String STATUS_APPROVED = "APPROVED";
    private static final String STATUS_REJECTED = "REJECTED";
    private static final String DOCUMENT_PERMISSION_REQUEST = "document_permission_request";

    @Override
    public String resolveToNodeId(String nodeIdOrPk) {
        if (nodeIdOrPk == null || nodeIdOrPk.isBlank()) {
            return nodeIdOrPk;
        }
        if (nodeIdOrPk.matches("^\\d+$")) {
            // 前端传的是 spaceNodeId，需通过 collabspace gRPC 解析为 dst nodeId
            Long spaceNodeId = Long.parseLong(nodeIdOrPk);
            String appNodeId = collabspaceGrpcClientService.getNodeIdBySpaceNodeId(spaceNodeId);
            ExceptionUtil.isNotBlank(appNodeId, PermissionException.NODE_NOT_EXIST);
            return appNodeId;
        }
        return nodeIdOrPk;
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public PermissionRequestVo submitRequest(String documentId, DocumentPermissionRequestRo ro) {
        Long applicantUserId = SessionContext.getUserId();
        ExceptionUtil.isNotNull(applicantUserId, PermissionException.NODE_ACCESS_DENIED);

        // 1. Check node exists and get spaceId
        String spaceId = iNodeService.checkNodeIfExist(null, documentId);
        NodeEntity node = iNodeService.getByNodeId(documentId);
        String documentName = node.getNodeName();

        // 2. Check user is in space
        Long memberId = iMemberService.getMemberIdByUserIdAndSpaceId(applicantUserId, spaceId);
        ExceptionUtil.isNotNull(memberId, PermissionException.MEMBER_NOT_IN_SPACE);

        // 3. Check no pending request for same document
        PermissionRequestEntity pending =
            baseMapper.selectPendingByDocumentAndApplicant(documentId, applicantUserId);
        ExceptionUtil.isNull(pending, NotificationException.ALREADY_SUBMITTED_REQUEST);

        // 4. Check user does not already have node permission
        // Try fetchInternalNodeRole first (stricter, matches frontend "no view permission")
        ControlRoleDict roleDict = controlTemplate.fetchInternalNodeRole(memberId, List.of(documentId));
        boolean hasPermission = !roleDict.isEmpty()
            && roleDict.get(documentId) != null
            && roleDict.get(documentId).hasPermission(NodePermission.READ_NODE);
        ExceptionUtil.isFalse(hasPermission, NotificationException.ALREADY_HAVE_PERMISSION);

        // 0. 防抖：短时间内重复提交同文档只处理一次
        String debounceKey = REDIS_DEBOUNCE_PREFIX + applicantUserId + ":" + documentId;
        Boolean firstSubmit = redisTemplate.opsForValue().setIfAbsent(debounceKey, "1", DEBOUNCE_SECONDS, TimeUnit.SECONDS);
        if (Boolean.FALSE.equals(firstSubmit)) {
            log.info("[1822-PermApply] debounce applicantUserId={} documentId={}", applicantUserId, documentId);
            throw new BusinessException(NotificationException.ALREADY_SUBMITTED_REQUEST);
        }

        // 5. Create permission request
        String requestId = REQUEST_ID_PREFIX + IdWorker.getId();
        PermissionRequestEntity entity = PermissionRequestEntity.builder()
            .id(requestId)
            .applicantUserId(applicantUserId)
            .documentId(documentId)
            .spaceId(spaceId)
            .requestedPermissionType(ro.getRequestedPermissionType())
            .status(STATUS_PENDING)
            .createdAt(LocalDateTime.now())
            .updatedAt(LocalDateTime.now())
            .build();

        boolean flag = SqlHelper.retBool(baseMapper.insert(entity));
        if (!flag) {
            log.error("[1822-PermApply] ERROR CREATE insert failed applicantUserId={} documentId={} spaceId={}", applicantUserId, documentId, spaceId);
            ExceptionUtil.isTrue(false, DatabaseException.INSERT_ERROR);
        }
        log.info("[1822-PermApply] CREATE request requestId={} applicantUserId={} documentId={} spaceId={} requestedType={}",
            requestId, applicantUserId, documentId, spaceId, ro.getRequestedPermissionType());

        // 6. Notify space admins & applicant (async)
        SpaceEntity space = iSpaceService.getBySpaceId(spaceId);
        String applicantNickName = iMemberService.getMemberNameByUserIdAndSpaceId(applicantUserId, spaceId);
        if (applicantNickName == null) {
            applicantNickName = "";
        }
        String finalDocumentName = documentName;
        String finalApplicantNickName = applicantNickName;
        String spaceName = space.getName() != null ? space.getName() : "";
        TaskManager.me().execute(() -> {
            notifyAdmins(entity, finalDocumentName, finalApplicantNickName, spaceName);
            notifyApplicant(entity, finalDocumentName, spaceName);
        });

        return buildVo(entity, documentName, space.getName());
    }

    /**
     * 通知所有对此文档有管理权限的用户（空间站管理员 + 文档节点管理员）.
     */
    private void notifyAdmins(PermissionRequestEntity request, String documentName, String applicantNickName, String spaceName) {
        try {
            List<com.apitable.workspace.vo.NodeRoleMemberVo> nodeRoleMembers =
                iNodeRoleService.getNodeRoleMembers(request.getSpaceId(), request.getDocumentId());
            List<Long> managerMemberIds = nodeRoleMembers.stream()
                .filter(m -> com.apitable.control.infrastructure.role.RoleConstants.Node.MANAGER.equals(m.getRole())
                    || Boolean.TRUE.equals(m.getIsWorkbenchAdmin()) || Boolean.TRUE.equals(m.getIsAdmin()))
                .map(com.apitable.workspace.vo.NodeRoleMemberVo::getMemberId)
                .distinct()
                .collect(Collectors.toList());
            if (CollUtil.isEmpty(managerMemberIds)) {
                log.warn("[1822-PermApply] notifyAdmins no managers documentId={}", request.getDocumentId());
                return;
            }

            List<Long> adminUserIds = notificationFactory.getMemberUserId(managerMemberIds, request.getSpaceId());
            if (CollUtil.isEmpty(adminUserIds)) {
                log.warn("[1822-PermApply] notifyAdmins no adminUserIds requestId={} spaceId={}", request.getId(), request.getSpaceId());
                return;
            }
            log.info("[1822-PermApply] notifyAdmins requestId={} documentId={} approverCount={}", request.getId(), request.getDocumentId(), adminUserIds.size());

            Map<String, Object> extras = new HashMap<>();
            extras.put("requestId", request.getId());
            extras.put("spaceName", spaceName);
            extras.put("applicantUserId", String.valueOf(request.getApplicantUserId()));
            extras.put("applicantNickName", applicantNickName);
            extras.put("documentId", request.getDocumentId());
            extras.put("documentName", documentName);
            extras.put("requestedPermissionType", request.getRequestedPermissionType());
            extras.put("status", request.getStatus());

            NotificationCreateRo ro = new NotificationCreateRo();
            ro.setTemplateId(NotificationTemplateId.DOCUMENT_PERMISSION_REQUEST.getValue());
            ro.setFromUserId(String.valueOf(request.getApplicantUserId()));
            ro.setToUserId(adminUserIds.stream().map(String::valueOf).collect(Collectors.toList()));
            ro.setNodeId(request.getDocumentId());
            ro.setSpaceId(request.getSpaceId());
            ro.setBody(JSONUtil.createObj().set(NotificationConstants.BODY_EXTRAS, extras));
            ro.setSendKnockNotification(true);

            playerNotificationService.createNotify(ro);
        } catch (Exception e) {
            log.error("[1822-PermApply] ERROR notifyAdmins requestId={} error={}", request.getId(), e.getMessage(), e);
        }
    }

    /**
     * Notify applicant that the permission request has been submitted.
     * Used for "APPLY" group in notification center (my applications).
     */
    private void notifyApplicant(PermissionRequestEntity request, String documentName, String spaceName) {
        try {
            Map<String, Object> extras = new HashMap<>();
            extras.put("requestId", request.getId());
            extras.put("documentId", request.getDocumentId());
            extras.put("documentName", documentName);
            extras.put("spaceId", request.getSpaceId());
            extras.put("spaceName", spaceName);
            extras.put("requestedPermissionType", request.getRequestedPermissionType());
            extras.put("status", request.getStatus());

            NotificationCreateRo ro = new NotificationCreateRo();
            ro.setTemplateId(NotificationTemplateId.PERMISSION_APPLY_SUBMITTED.getValue());
            // fromUserId 设为 0，避免 createNotifyWithoutVerify 中“不给自己发站内信”的过滤
            ro.setFromUserId("0");
            ro.setToUserId(Collections.singletonList(String.valueOf(request.getApplicantUserId())));
            ro.setNodeId(request.getDocumentId());
            ro.setSpaceId(request.getSpaceId());
            ro.setBody(JSONUtil.createObj().set(NotificationConstants.BODY_EXTRAS, extras));

            playerNotificationService.createNotify(ro);
            log.info("[1822-PermApply] notifyApplicant requestId={} applicantUserId={} documentId={}", request.getId(), request.getApplicantUserId(), request.getDocumentId());
        } catch (Exception e) {
            log.error("[1822-PermApply] ERROR notifyApplicant requestId={} error={}", request.getId(), e.getMessage(), e);
        }
    }

    private PermissionRequestVo buildVo(PermissionRequestEntity entity, String documentName, String spaceName) {
        return PermissionRequestVo.builder()
            .id(entity.getId())
            .documentId(entity.getDocumentId())
            .documentName(documentName)
            .spaceId(entity.getSpaceId())
            .spaceName(spaceName)
            .requestedPermissionType(entity.getRequestedPermissionType())
            .status(entity.getStatus())
            .createdAt(entity.getCreatedAt())
            .build();
    }

    @Override
    public List<PermissionRequestVo> getMyRequests(Long userId, String status, int page, int pageSize) {
        int offset = (page - 1) * pageSize;
        List<PermissionRequestEntity> entities =
            baseMapper.selectByApplicantUserId(userId, status, offset, pageSize);
        if (CollUtil.isEmpty(entities)) {
            return ListUtil.empty();
        }
        return entities.stream().map(e -> {
            String docName = "";
            String spaceName = "";
            try {
                NodeEntity node = iNodeService.getByNodeId(e.getDocumentId());
                docName = node != null ? node.getNodeName() : "";
            } catch (Exception ex) {
                log.debug("Node not found: {}", e.getDocumentId());
            }
            try {
                SpaceEntity space = iSpaceService.getBySpaceId(e.getSpaceId());
                spaceName = space != null ? space.getName() : "";
            } catch (Exception ex) {
                log.debug("Space not found: {}", e.getSpaceId());
            }
            return buildVo(e, docName, spaceName);
        }).collect(Collectors.toList());
    }

    @Override
    public int countMyRequests(Long userId, String status) {
        return baseMapper.countByApplicantUserId(userId, status);
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public void approve(Long notificationId, Long approverUserId) {
        PermissionRequestEntity request = validateAndGetRequest(notificationId, approverUserId);
        // 获取文档名称
        NodeEntity node = iNodeService.getByNodeId(request.getDocumentId());
        String documentName = node != null ? node.getNodeName() : "";
        String approverNickName = iMemberService.getMemberNameByUserIdAndSpaceId(approverUserId, request.getSpaceId());
        if (approverNickName == null) {
            approverNickName = "";
        }
        final String finalApproverNickName = approverNickName;
        // Add node role for applicant
        String nodeRole = mapPermissionTypeToNodeRole(request.getRequestedPermissionType());
        Long applicantMemberId = iMemberService.getMemberIdByUserIdAndSpaceId(request.getApplicantUserId(), request.getSpaceId());
        ExceptionUtil.isNotNull(applicantMemberId, PermissionException.MEMBER_NOT_IN_SPACE);
        Long unitId = iUnitService.getUnitIdByRefId(applicantMemberId);
        ExceptionUtil.isNotNull(unitId, NotificationException.APPLICANT_UNIT_NOT_FOUND);
        iNodeRoleService.addNodeRole(approverUserId, request.getDocumentId(), nodeRole, Collections.singletonList(unitId));

        // 同步权限到 collabspace，让 spaceNodeInfo 放行
        Long spaceNodeId = collabspaceGrpcClientService.getSpaceNodeIdByNodeId(request.getDocumentId());
        if (spaceNodeId != null) {
            collabspaceGrpcClientService.grantNodePermission(
                request.getApplicantUserId(),
                request.getSpaceId(),
                spaceNodeId,
                nodeRole,
                Collections.singletonList(unitId)
            );
        } else {
            log.warn("[1822-PermApply] approve sync skipped spaceNodeId=null documentId={}", request.getDocumentId());
        }

        // Update PermissionRequest
        baseMapper.updateStatusById(request.getId(), STATUS_APPROVED, approverUserId);

        // 更新通知 body 的 extras，使列表接口返回正确的 status（前端据此显示「已同意」）
        updateNotificationExtras(notificationId, STATUS_APPROVED, approverUserId, finalApproverNickName);

        // Notify applicant
        TaskManager.me().execute(() -> NotificationManager.me().playerNotify(
            NotificationTemplateId.PERMISSION_APPROVED,
            Collections.singletonList(request.getApplicantUserId()),
            approverUserId,
            request.getSpaceId(),
            Map.of(
                "requestId", request.getId(),
                "documentId", request.getDocumentId(),
                "documentName", documentName,
                "status", STATUS_APPROVED,
                "approverUserId", String.valueOf(approverUserId),
                "approverNickName", finalApproverNickName
            )));

        // Mark notification as read
        playerNotificationService.setNotificationIsRead(new String[]{String.valueOf(notificationId)}, 0);
        log.info("[1822-PermApply] APPROVE requestId={} approverUserId={} applicantUserId={} documentId={} nodeRole={}",
            request.getId(), approverUserId, request.getApplicantUserId(), request.getDocumentId(), nodeRole);
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public void reject(Long notificationId, Long approverUserId) {
        PermissionRequestEntity request = validateAndGetRequest(notificationId, approverUserId);
        NodeEntity node = iNodeService.getByNodeId(request.getDocumentId());
        String documentName = node != null ? node.getNodeName() : "";
        String approverNickName = iMemberService.getMemberNameByUserIdAndSpaceId(approverUserId, request.getSpaceId());
        if (approverNickName == null) {
            approverNickName = "";
        }
        final String finalApproverNickName = approverNickName;
        baseMapper.updateStatusById(request.getId(), STATUS_REJECTED, approverUserId);

        // 更新通知 body 的 extras，使列表接口返回正确的 status（前端据此显示「已拒绝」）
        updateNotificationExtras(notificationId, STATUS_REJECTED, approverUserId, finalApproverNickName);

        log.info("[1822-PermApply] REJECT requestId={} approverUserId={} applicantUserId={} documentId={}",
            request.getId(), approverUserId, request.getApplicantUserId(), request.getDocumentId());

        TaskManager.me().execute(() -> NotificationManager.me().playerNotify(
            NotificationTemplateId.PERMISSION_REJECTED,
            Collections.singletonList(request.getApplicantUserId()),
            approverUserId,
            request.getSpaceId(),
            Map.of(
                "requestId", request.getId(),
                "documentId", request.getDocumentId(),
                "documentName", documentName,
                "status", STATUS_REJECTED,
                "approverUserId", String.valueOf(approverUserId),
                "approverNickName", finalApproverNickName
            )));

        playerNotificationService.setNotificationIsRead(new String[]{String.valueOf(notificationId)}, 0);
    }

    @Override
    public void ignore(Long notificationId, Long approverUserId) {
        validateNotificationForApprover(notificationId, approverUserId);
        playerNotificationService.setNotificationIsRead(new String[]{String.valueOf(notificationId)}, 0);
        log.info("[1822-PermApply] IGNORE notificationId={} approverUserId={}", notificationId, approverUserId);
    }

    @Override
    public void reapprove(Long notificationId, Long approverUserId) {
        validateNotificationForApprover(notificationId, approverUserId);
        playerNotificationMapper.updateReadIsFalseByIdAndToUser(notificationId, approverUserId);
        log.info("[1822-PermApply] REAPPROVE notificationId={} approverUserId={}", notificationId, approverUserId);
    }

    private PermissionRequestEntity validateAndGetRequest(Long notificationId, Long approverUserId) {
        String requestId = getRequestIdFromNotification(notificationId, approverUserId);
        if (requestId == null || requestId.isBlank()) {
            log.warn("[1822-PermApply] validate fail notificationInvalid notificationId={} approverUserId={}", notificationId, approverUserId);
            ExceptionUtil.isNotBlank(requestId, NotificationException.NOTIFICATION_NOT_VALID);
        }
        PermissionRequestEntity request = baseMapper.selectById(requestId);
        if (request == null) {
            log.warn("[1822-PermApply] validate fail requestNotFound requestId={} notificationId={}", requestId, notificationId);
            ExceptionUtil.isNotNull(request, NotificationException.PERMISSION_REQUEST_NOT_FOUND);
        }
        if (!STATUS_PENDING.equals(request.getStatus())) {
            log.warn("[1822-PermApply] validate fail alreadyProcessed requestId={} status={}", request.getId(), request.getStatus());
            ExceptionUtil.isTrue(false, NotificationException.REQUEST_ALREADY_PROCESSED);
        }
        validateApproverIsAdmin(approverUserId, request.getSpaceId());
        return request;
    }

    private void validateNotificationForApprover(Long notificationId, Long approverUserId) {
        String requestId = getRequestIdFromNotification(notificationId, approverUserId);
        if (requestId == null || requestId.isBlank()) {
            log.warn("[1822-PermApply] validate fail notificationInvalid notificationId={} approverUserId={}", notificationId, approverUserId);
            ExceptionUtil.isNotBlank(requestId, NotificationException.NOTIFICATION_NOT_VALID);
        }
        PermissionRequestEntity request = baseMapper.selectById(requestId);
        if (request == null) {
            log.warn("[1822-PermApply] validate fail requestNotFound requestId={} notificationId={}", requestId, notificationId);
            ExceptionUtil.isNotNull(request, NotificationException.PERMISSION_REQUEST_NOT_FOUND);
        }
        validateApproverIsAdmin(approverUserId, request.getSpaceId());
    }

    /**
     * 更新审批通知的 notify_body.extras，使列表接口返回正确的 status（前端据此区分已同意/已拒绝/已忽略）
     */
    private void updateNotificationExtras(Long notificationId, String status, Long approverUserId, String approverNickName) {
        try {
            String bodyStr = playerNotificationMapper.selectNotifyBodyById(notificationId);
            if (bodyStr == null || bodyStr.isBlank()) return;
            JSONObject body = JSONUtil.parseObj(bodyStr);
            JSONObject extras = body.getJSONObject(NotificationConstants.BODY_EXTRAS);
            if (extras == null) extras = new JSONObject();
            extras.set("status", status);
            extras.set("approverUserId", String.valueOf(approverUserId));
            extras.set("approverNickName", approverNickName != null ? approverNickName : "");
            body.set(NotificationConstants.BODY_EXTRAS, extras);
            playerNotificationMapper.updateNotifyBodyById(notificationId, body.toString());
        } catch (Exception e) {
            log.warn("[1822-PermApply] updateNotificationExtras failed notificationId={} status={} error={}", notificationId, status, e.getMessage(), e);
        }
    }

    private String getRequestIdFromNotification(Long notificationId, Long approverUserId) {
        com.apitable.player.entity.PlayerNotificationEntity notification =
            playerNotificationService.getById(notificationId);
        if (notification == null || !approverUserId.equals(notification.getToUser())) {
            return null;
        }
        if (!DOCUMENT_PERMISSION_REQUEST.equals(notification.getTemplateId())) {
            return null;
        }
        String body = notification.getNotifyBody();
        if (body == null) {
            return null;
        }
        JSONObject json = JSONUtil.parseObj(body);
        JSONObject extras = json.getJSONObject(NotificationConstants.BODY_EXTRAS);
        if (extras == null) {
            return null;
        }
        return extras.getStr("requestId");
    }

    private void validateApproverIsAdmin(Long approverUserId, String spaceId) {
        var userSpace = userSpaceCacheService.getUserSpace(approverUserId, spaceId);
        ExceptionUtil.isNotNull(userSpace, SpaceException.NOT_IN_SPACE);
        ExceptionUtil.isTrue(CollUtil.contains(userSpace.getResourceCodes(), "INVITE_MEMBER"),
            SpacePermissionException.INSUFFICIENT_PERMISSIONS);
    }

    private String mapPermissionTypeToNodeRole(String requestedPermissionType) {
        return switch (requestedPermissionType) {
            case "READ" -> Node.READER;
            case "EDIT" -> Node.EDITOR;
            case "MANAGE" -> Node.MANAGER;
            default -> Node.READER;
        };
    }
}

package com.yottastudios.ns.collabspace.control.service.impl;

import cn.hutool.core.collection.CollUtil;
import cn.hutool.core.util.IdUtil;
import cn.hutool.json.JSONUtil;
import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
import com.yottastudios.ns.collabspace.control.entity.ControlRoleEntity;
import com.yottastudios.ns.collabspace.control.entity.PermissionRequestEntity;
import com.yottastudios.ns.collabspace.control.enums.PermissionRequestException;
import com.yottastudios.ns.collabspace.control.mapper.PermissionRequestMapper;
import com.yottastudios.ns.collabspace.control.ro.DocumentPermissionRequestRo;
import com.yottastudios.ns.collabspace.control.service.IControlRoleService;
import com.yottastudios.ns.collabspace.control.service.IControlService;
import com.yottastudios.ns.collabspace.control.service.IPermissionRequestService;
import com.yottastudios.ns.collabspace.control.vo.PermissionRequestVo;
import com.yottastudios.ns.collabspace.core.exception.BusinessException;
import com.yottastudios.ns.collabspace.core.util.ExceptionUtil;
import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
import com.yottastudios.ns.collabspace.organization.vo.UnitMemberVo;
import com.yottastudios.ns.collabspace.shared.context.SessionContext;
import com.yottastudios.ns.collabspace.space.entity.SpaceEntity;
import com.yottastudios.ns.collabspace.space.manager.query.SpaceQueryManager;
import com.yottastudios.ns.collabspace.space.service.ISpaceService;
import com.yottastudios.ns.collabspace.user.vo.UserSimpleInfoVo;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
import com.yottastudios.ns.collabspace.workspace.manager.query.NodeRoleQueryManager;
import com.yottastudios.ns.collabspace.workspace.manager.update.NodeRoleUpdateManager;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeService;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;
import java.util.*;
import java.util.concurrent.TimeUnit;
import java.util.stream.Collectors;

import static com.yottastudios.ns.collabspace.control.infrastructure.role.RoleConstants.Node.EDITOR;
import static com.yottastudios.ns.collabspace.control.infrastructure.role.RoleConstants.Node.MANAGER;
import static com.yottastudios.ns.collabspace.control.infrastructure.role.RoleConstants.Node.READER;

/**
 * Permission request service implementation.
 * Full implementation migrated from apitable-backend-server.
 * All notifications are sent to apitable via gRPC.
 */
@Slf4j
@Service
public class PermissionRequestServiceImpl extends ServiceImpl<PermissionRequestMapper, PermissionRequestEntity>
    implements IPermissionRequestService {

    private static final String STATUS_PENDING = "PENDING";
    private static final String STATUS_APPROVED = "APPROVED";
    private static final String STATUS_REJECTED = "REJECTED";
    private static final String REQUEST_ID_PREFIX = "req_";

    private static final String REDIS_DEBOUNCE_PREFIX = "permission_apply_debounce:";
    private static final long DEBOUNCE_SECONDS = 10;

    private static final String DOCUMENT_PERMISSION_REQUEST = "document_permission_request";
    private static final String BODY_EXTRAS = "extras";

    @Resource
    private IControlService controlService;

    @Resource
    private ISpaceService spaceService;

    @Resource
    private ISpaceNodeService spaceNodeService;

    @Resource
    private SpaceQueryManager spaceQueryManager;

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;

    @Resource
    private RedisTemplate<String, Object> redisTemplate;

    @Resource
    private NodeRoleUpdateManager nodeRoleUpdateManager;

    @Resource
    private NodeRoleQueryManager nodeRoleQueryManager;

    @Resource
    private IControlRoleService controlRoleService;

    // ========== submitRequest ==========

    @Override
    @Transactional(rollbackFor = Exception.class)
    public PermissionRequestVo submitRequest(String documentId, DocumentPermissionRequestRo ro) {
        Long applicantUserId = SessionContext.getUserId();
        ExceptionUtil.isNotNull(applicantUserId, PermissionRequestException.NODE_ACCESS_DENIED);
        ExceptionUtil.isNotNull(documentId, PermissionRequestException.NODE_NOT_EXIST);

        // 1. Check node exists and get spaceId; resolve numeric pk to appSpaceNodeId
        SpaceNodeEntity spaceNode = getSpaceNodeByNodeId(documentId);
        String resolvedDocumentId = spaceNode.getAppSpaceNodeId();
        String spaceId = spaceNode.getSpaceId();
        String documentName = spaceNode.getName();

        // 2. Check user is in space
        boolean isInSpace = spaceQueryManager.isUserInSpace(applicantUserId, spaceId);
        ExceptionUtil.isTrue(isInSpace, PermissionRequestException.MEMBER_NOT_IN_SPACE);

        // 3. Check no pending request for same document
        PermissionRequestEntity pending = baseMapper.selectPendingByDocumentAndApplicant(resolvedDocumentId, applicantUserId);
        ExceptionUtil.isNull(pending, PermissionRequestException.ALREADY_SUBMITTED_REQUEST);

        // 4. Check user does not already have node permission
        boolean hasPermission = checkUserHasNodePermission(spaceId, applicantUserId, resolvedDocumentId);
        ExceptionUtil.isFalse(hasPermission, PermissionRequestException.ALREADY_HAVE_PERMISSION);

        // 5. Debounce: short period repeated submissions only processed once
        String debounceKey = REDIS_DEBOUNCE_PREFIX + applicantUserId + ":" + resolvedDocumentId;
        Boolean firstSubmit = redisTemplate.opsForValue().setIfAbsent(debounceKey, "1", DEBOUNCE_SECONDS, TimeUnit.SECONDS);
        if (Boolean.FALSE.equals(firstSubmit)) {
            log.info("[1822-PermApply] debounce applicantUserId={} documentId={}", applicantUserId, documentId);
            throw new BusinessException(PermissionRequestException.ALREADY_SUBMITTED_REQUEST);
        }

        // 6. Create permission request record
        String requestId = REQUEST_ID_PREFIX + IdUtil.getSnowflakeNextId();
        PermissionRequestEntity entity = PermissionRequestEntity.builder()
            .id(requestId)
            .applicantUserId(applicantUserId)
            .documentId(resolvedDocumentId)
            .spaceId(spaceId)
            .requestedPermissionType(ro.getRequestedPermissionType())
            .status(STATUS_PENDING)
            .createdAt(LocalDateTime.now())
            .updatedAt(LocalDateTime.now())
            .build();

        boolean flag = save(entity);
        if (!flag) {
            log.error("[1822-PermApply] ERROR CREATE insert failed applicantUserId={} documentId={} spaceId={}",
                applicantUserId, resolvedDocumentId, spaceId);
            throw new BusinessException(PermissionRequestException.INSERT_ERROR);
        }
        log.info("[1822-PermApply] CREATE request requestId={} applicantUserId={} documentId={} spaceId={} requestedType={}",
            requestId, applicantUserId, resolvedDocumentId, spaceId, ro.getRequestedPermissionType());

        // 7. Get space name and applicant nickname
        SpaceEntity space = spaceService.getBySpaceId(spaceId);
        String spaceName = space != null && space.getName() != null ? space.getName() : "";
        String applicantNickName = getApplicantNickName(applicantUserId);

        // 8. Notify admins & applicant via apitable gRPC (async)
        notifyAdminsAsync(entity, documentName, applicantNickName, spaceName);
        notifyApplicantAsync(entity, documentName, spaceName);

        return buildVo(entity, documentName, spaceName);
    }

    private SpaceNodeEntity getSpaceNodeByNodeId(String nodeId) {
        if (nodeId != null && nodeId.matches("^\\d+$")) {
            SpaceNodeEntity node = spaceNodeService.getByIdAllStatus(Long.parseLong(nodeId));
            ExceptionUtil.isNotNull(node, PermissionRequestException.NODE_NOT_EXIST);
            return node;
        }
        List<SpaceNodeEntity> nodes = spaceNodeService.listByAppSpaceNodeIds(Collections.singletonList(nodeId));
        ExceptionUtil.isNotEmpty(nodes, PermissionRequestException.NODE_NOT_EXIST);
        return nodes.get(0);
    }

    private SpaceNodeEntity getSpaceNodeByNodeIdSafe(String nodeId) {
        if (nodeId != null && nodeId.matches("^\\d+$")) {
            return spaceNodeService.getByIdAllStatus(Long.parseLong(nodeId));
        }
        List<SpaceNodeEntity> nodes = spaceNodeService.listByAppSpaceNodeIds(Collections.singletonList(nodeId));
        return CollUtil.isNotEmpty(nodes) ? nodes.get(0) : null;
    }

    /**
     * Check if user has at least READ permission on the node.
     */
    private boolean checkUserHasNodePermission(String spaceId, Long userId, String documentId) {
        try {
            boolean exists = controlService.existsByControlId(documentId);
            if (!exists) {
                return false;
            }
            UnitMemberVo memberVo = apitableGrpcClientService.findUnitMemberVo(List.of(userId), spaceId)
                .stream().findFirst().orElse(null);
            if (memberVo == null || memberVo.getUnitId() == null) {
                return false;
            }
            List<ControlRoleEntity> roles = controlRoleService.getByControlIdAndUnitIds(
                documentId, Collections.singletonList(memberVo.getUnitId()));
            return CollUtil.isNotEmpty(roles);
        } catch (Exception e) {
            log.debug("[1822-PermApply] checkUserHasNodePermission error userId={} documentId={}", userId, documentId);
            return false;
        }
    }

    private String getApplicantNickName(Long userId) {
        try {
            UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
            if (user != null && user.getNickName() != null) {
                return user.getNickName();
            }
            return "用户" + userId;
        } catch (Exception e) {
            log.warn("[1822-PermApply] getApplicantNickName error userId={}", userId, e);
            return "用户" + userId;
        }
    }

    // ========== Notification via gRPC ==========

    @Async
    public void notifyAdminsAsync(PermissionRequestEntity request, String documentName,
                                   String applicantNickName, String spaceName) {
        try {
            List<Long> adminUserIds = spaceQueryManager.getAdminUsersWithWorkBenchManagePermission(request.getSpaceId());
            if (CollUtil.isEmpty(adminUserIds)) {
                log.warn("[1822-PermApply] notifyAdmins no admins spaceId={}", request.getSpaceId());
                return;
            }
            log.info("[1822-PermApply] notifyAdmins requestId={} documentId={} approverCount={}",
                request.getId(), request.getDocumentId(), adminUserIds.size());

            Map<String, Object> extras = new HashMap<>();
            extras.put("requestId", request.getId());
            extras.put("spaceName", spaceName);
            extras.put("applicantUserId", String.valueOf(request.getApplicantUserId()));
            extras.put("applicantNickName", applicantNickName);
            extras.put("documentId", request.getDocumentId());
            extras.put("documentName", documentName);
            extras.put("requestedPermissionType", request.getRequestedPermissionType());
            extras.put("status", request.getStatus());

            Map<String, Object> bodyMap = new HashMap<>();
            bodyMap.put(BODY_EXTRAS, extras);
            String bodyJson = JSONUtil.toJsonStr(bodyMap);

            apitableGrpcClientService.createNotification(
                DOCUMENT_PERMISSION_REQUEST,
                String.valueOf(request.getApplicantUserId()),
                adminUserIds.stream().map(String::valueOf).collect(Collectors.toList()),
                request.getDocumentId(),
                request.getSpaceId(),
                bodyJson,
                true
            );

            log.info("[1822-PermApply] notifyAdmins done requestId={} adminCount={}", request.getId(), adminUserIds.size());
        } catch (Exception e) {
            log.error("[1822-PermApply] ERROR notifyAdmins requestId={} error={}", request.getId(), e.getMessage(), e);
        }
    }

    @Async
    public void notifyApplicantAsync(PermissionRequestEntity request, String documentName, String spaceName) {
        try {
            Map<String, Object> extras = new HashMap<>();
            extras.put("requestId", request.getId());
            extras.put("documentId", request.getDocumentId());
            extras.put("documentName", documentName);
            extras.put("spaceId", request.getSpaceId());
            extras.put("spaceName", spaceName);
            extras.put("requestedPermissionType", request.getRequestedPermissionType());
            extras.put("status", request.getStatus());

            Map<String, Object> bodyMap = new HashMap<>();
            bodyMap.put(BODY_EXTRAS, extras);
            String bodyJson = JSONUtil.toJsonStr(bodyMap);

            // fromUserId = "0" avoids apitable's "don't notify self" filter
            apitableGrpcClientService.createNotification(
                "permission_apply_submitted",
                "0",
                Collections.singletonList(String.valueOf(request.getApplicantUserId())),
                request.getDocumentId(),
                request.getSpaceId(),
                bodyJson,
                false
            );

            log.info("[1822-PermApply] notifyApplicant requestId={} applicantUserId={} documentId={}",
                request.getId(), request.getApplicantUserId(), request.getDocumentId());
        } catch (Exception e) {
            log.error("[1822-PermApply] ERROR notifyApplicant requestId={} error={}", request.getId(), e.getMessage(), e);
        }
    }

    // ========== List / Count ==========

    @Override
    public List<PermissionRequestVo> getMyRequests(Long userId, String status, int page, int pageSize) {
        int offset = (page - 1) * pageSize;
        List<PermissionRequestEntity> entities = baseMapper.selectByApplicantUserId(userId, status, offset, pageSize);
        if (CollUtil.isEmpty(entities)) {
            return Collections.emptyList();
        }
        return entities.stream().map(e -> {
            String docName = "";
            String spaceName = "";
            try {
                SpaceNodeEntity node = getSpaceNodeByNodeIdSafe(e.getDocumentId());
                docName = node != null ? node.getName() : "";
            } catch (Exception ex) {
                log.debug("[1822-PermApply] Node not found: {}", e.getDocumentId());
            }
            try {
                SpaceEntity space = spaceService.getBySpaceId(e.getSpaceId());
                spaceName = space != null && space.getName() != null ? space.getName() : "";
            } catch (Exception ex) {
                log.debug("[1822-PermApply] Space not found: {}", e.getSpaceId());
            }
            return buildVo(e, docName, spaceName);
        }).collect(Collectors.toList());
    }

    @Override
    public int countMyRequests(Long userId, String status) {
        return baseMapper.countByApplicantUserId(userId, status);
    }

    // ========== Legacy methods (not used - kept for interface compatibility) ==========

    @Override
    public void approve(Long notificationId, Long approverUserId) {
        throw new UnsupportedOperationException("Use approveByRequestId instead");
    }

    @Override
    public void reject(Long notificationId, Long approverUserId) {
        throw new UnsupportedOperationException("Use rejectByRequestId instead");
    }

    // ========== Approve / Reject (by requestId) ==========

    @Override
    @Transactional(rollbackFor = Exception.class)
    public void approveByRequestId(String requestId, Long notificationId, Long approverUserId) {
        PermissionRequestEntity request = validateAndGetRequest(requestId, approverUserId);

        String approverNickName = getApproverNickName(approverUserId);

        // Get applicant unitId
        UnitMemberVo applicantMember = apitableGrpcClientService.findUnitMemberVo(
                List.of(request.getApplicantUserId()), request.getSpaceId())
            .stream().findFirst().orElse(null);
        ExceptionUtil.isNotNull(applicantMember, PermissionRequestException.APPLICANT_UNIT_NOT_FOUND);
        Long unitId = applicantMember.getUnitId();
        ExceptionUtil.isNotNull(unitId, PermissionRequestException.APPLICANT_UNIT_NOT_FOUND);

        // Map permission type to node role
        String nodeRole = mapPermissionTypeToNodeRole(request.getRequestedPermissionType());

        // Add node role
        Long spaceNodeId = parseSpaceNodeId(request.getDocumentId());
        if (spaceNodeId != null) {
            nodeRoleUpdateManager.addNodeRole(approverUserId, request.getSpaceId(), spaceNodeId, nodeRole,
                Collections.singletonList(unitId));
        }

        // Update permission request status in collabspace
        baseMapper.updateStatusById(request.getId(), STATUS_APPROVED, approverUserId);

        // Update notification extras in apitable (via gRPC)
        apitableGrpcClientService.updateNotificationExtras(notificationId, STATUS_APPROVED,
            String.valueOf(approverUserId), approverNickName);

        // Mark notification as read in apitable (via gRPC)
        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);

        log.info("[1822-PermApply] APPROVE requestId={} approverUserId={} applicantUserId={} documentId={} nodeRole={}",
            request.getId(), approverUserId, request.getApplicantUserId(), request.getDocumentId(), nodeRole);
    }

    @Override
    @Transactional(rollbackFor = Exception.class)
    public void rejectByRequestId(String requestId, Long notificationId, Long approverUserId) {
        PermissionRequestEntity request = validateAndGetRequest(requestId, approverUserId);

        String approverNickName = getApproverNickName(approverUserId);

        // Update permission request status
        baseMapper.updateStatusById(request.getId(), STATUS_REJECTED, approverUserId);

        // Update notification extras in apitable (via gRPC)
        apitableGrpcClientService.updateNotificationExtras(notificationId, STATUS_REJECTED,
            String.valueOf(approverUserId), approverNickName);

        // Mark notification as read in apitable (via gRPC)
        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);

        log.info("[1822-PermApply] REJECT requestId={} approverUserId={} applicantUserId={} documentId={}",
            request.getId(), approverUserId, request.getApplicantUserId(), request.getDocumentId());
    }

    @Override
    public void ignoreByRequestId(String requestId, Long notificationId, Long approverUserId) {
        validateRequestForApprover(requestId, approverUserId);
        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, true);
        log.info("[1822-PermApply] IGNORE requestId={} notificationId={} approverUserId={}", requestId, notificationId, approverUserId);
    }

    @Override
    public void reapproveByRequestId(String requestId, Long notificationId, Long approverUserId) {
        validateRequestForApprover(requestId, approverUserId);
        apitableGrpcClientService.setNotificationRead(notificationId, approverUserId, false);
        log.info("[1822-PermApply] REAPPROVE requestId={} notificationId={} approverUserId={}", requestId, notificationId, approverUserId);
    }

    // ========== Validation Helpers ==========

    /**
     * Validates requestId exists and approver is admin. Does NOT check PENDING status.
     * Used for reapprove, which can act on already-processed requests.
     */
    private void validateRequestForApprover(String requestId, Long approverUserId) {
        if (requestId == null || requestId.isBlank()) {
            ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
        }
        PermissionRequestEntity request = baseMapper.selectById(requestId);
        if (request == null) {
            log.warn("[1822-PermApply] validate requestNotFound requestId={}", requestId);
            ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
        }
        validateApproverIsAdmin(approverUserId, request.getSpaceId());
    }

    private PermissionRequestEntity validateAndGetRequest(String requestId, Long approverUserId) {
        if (requestId == null || requestId.isBlank()) {
            ExceptionUtil.isNotBlank(requestId, PermissionRequestException.NOTIFICATION_NOT_VALID);
        }
        PermissionRequestEntity request = baseMapper.selectById(requestId);
        if (request == null) {
            log.warn("[1822-PermApply] validate requestNotFound requestId={}", requestId);
            ExceptionUtil.isNotNull(request, PermissionRequestException.PERMISSION_REQUEST_NOT_FOUND);
        }
        if (!STATUS_PENDING.equals(request.getStatus())) {
            log.warn("[1822-PermApply] validate alreadyProcessed requestId={} status={}",
                request.getId(), request.getStatus());
            ExceptionUtil.isTrue(false, PermissionRequestException.REQUEST_ALREADY_PROCESSED);
        }
        validateApproverIsAdmin(approverUserId, request.getSpaceId());
        return request;
    }

    private void validateApproverIsAdmin(Long approverUserId, String spaceId) {
        boolean isAdmin = spaceQueryManager.isUserSpaceAdmin(approverUserId, spaceId);
        ExceptionUtil.isTrue(isAdmin, PermissionRequestException.INSUFFICIENT_PERMISSIONS);
    }

    private String getApproverNickName(Long approverUserId) {
        try {
            UserSimpleInfoVo user = apitableGrpcClientService.getUserById(approverUserId);
            return user != null && user.getNickName() != null ? user.getNickName() : "";
        } catch (Exception e) {
            return "";
        }
    }

    private Long parseSpaceNodeId(String documentId) {
        try {
            return Long.parseLong(documentId);
        } catch (NumberFormatException e) {
            return getSpaceNodeIdByAppNodeId(documentId);
        }
    }

    private Long getSpaceNodeIdByAppNodeId(String appNodeId) {
        try {
            List<SpaceNodeEntity> nodes = spaceNodeService.listByAppSpaceNodeIds(Collections.singletonList(appNodeId));
            if (CollUtil.isNotEmpty(nodes)) {
                return nodes.get(0).getId();
            }
        } catch (Exception e) {
            log.warn("[1822-PermApply] getSpaceNodeIdByAppNodeId failed appNodeId={}", appNodeId, e);
        }
        return null;
    }

    private String mapPermissionTypeToNodeRole(String requestedPermissionType) {
        return switch (requestedPermissionType) {
            case "READ" -> READER;
            case "EDIT" -> EDITOR;
            case "MANAGE" -> MANAGER;
            default -> READER;
        };
    }

    private PermissionRequestVo buildVo(PermissionRequestEntity entity, String documentName, String spaceName) {
        return PermissionRequestVo.builder()
            .id(entity.getId())
            .documentId(entity.getDocumentId())
            .documentName(documentName)
            .spaceId(entity.getSpaceId())
            .spaceName(spaceName)
            .requestedPermissionType(entity.getRequestedPermissionType())
            .status(entity.getStatus())
            .createdAt(entity.getCreatedAt())
            .build();
    }
}

